    <script>
        document.addEventListener('DOMContentLoaded', () => {
            // Thay thế dấu '_' thành khoảng trắng trên giao diện (không làm ảnh hưởng ID, Value hay Schema)
const walker = document.createTreeWalker(document.getElementById('creator-card'), NodeFilter.SHOW_TEXT, null, false);
let node;
while (node = walker.nextNode()) {
    node.nodeValue = node.nodeValue.replace(/_/g, ' ');
}
            const form = document.getElementById('creator-form');
            const generateBtn = document.getElementById('generate-btn');
            const resetFormBtn = document.getElementById('reset-form-btn');
            const notification = document.getElementById('copy-notification');
            const creatorCard = document.getElementById('creator-card');
            const colorPicker = document.getElementById('char-color-picker');
            const colorText = document.getElementById('char-color-text');
            const personalityRadios = document.querySelectorAll('input[name="personality-state"]');
            const masterField = document.getElementById('master-field');
            const initialButtonHTML = generateBtn.innerHTML;
            const allInputs = Array.from(form.querySelectorAll('input, textarea, select'));

            const profileSelect = document.getElementById('profile-select');
            const loadProfileBtn = document.getElementById('load-profile-btn');
            const saveProfileBtn = document.getElementById('save-profile-btn');
            const deleteProfileBtn = document.getElementById('delete-profile-btn');
            const exportProfilesBtn = document.getElementById('export-profiles-btn');
            const importProfilesBtn = document.getElementById('import-profiles-btn');
            const importFileInput = document.getElementById('import-file-input');

            // --- Cấu hình ---
            const AUTOSAVE_KEY = 'magicalGirl_AutoSave_v3';
            const PROFILE_STORAGE_KEY = 'magicalGirl_ProfileManager_v3';

            // Key tương thích (Dùng để đọc dữ liệu bản cũ)
            const OLD_KEYS = [
                'magicalGirl_AutoSave',             
                'magicalGirl_ProfileManager',       
                'magicalGirl_AutoSave_v4',          
                'magicalGirl_Profiles_v4',
                'magicalGirl_AutoSave_v2',
                'magicalGirl_ProfileManager_v2'
            ];

            let saveTimeout;

            // --- Logic tự động điều chỉnh độ cao hộp văn bản ---
            const textareas = document.querySelectorAll('textarea');
            const autoResizeTextarea = (ta) => {
                ta.style.height = 'auto'; // Đưa về 0 trước
                ta.style.height = ta.scrollHeight + 'px'; // Mở rộng dựa theo nội dung
            };
            textareas.forEach(ta => {
                ta.addEventListener('input', () => autoResizeTextarea(ta));
            });

            const showNotification = (message, color = 'var(--success-color)') => {
                notification.textContent = message;
                notification.style.color = color;
                notification.style.opacity = '1';
                clearTimeout(notification.timeoutId);
                notification.timeoutId = setTimeout(() => { notification.style.opacity = '0'; }, 3000);
            };

            const updateUIState = () => {
                const selectedRadio = document.querySelector('input[name="personality-state"]:checked');
                const isFallen = selectedRadio?.value === 'Sa_ngã';
                creatorCard.classList.toggle('theme-fallen', isFallen);
                if (isFallen) {
                    masterField.classList.add('visible');
                } else {
                    masterField.classList.remove('visible');
                }
            };

            const getCurrentFormData = () => {
                const data = {};
                allInputs.forEach(input => {
                    if (input.type === 'radio') {
                        if (input.checked) data[input.name] = input.value;
                    } else if (input.id) {
                        data[input.id] = input.value;
                    }
                });
                return data;
            };

            const populateForm = (data) => {
                if (!data) return;
                allInputs.forEach(input => {
                    const key = (input.type === 'radio') ? input.name : (input.id || input.name);
                    if (data[key] !== undefined) {
                        if (input.type === 'radio') {
                           input.checked = (input.value === data[key]);
                        } else {
                           input.value = data[key];
                        }
                    } else {
                        // Bỏ qua dữ liệu không hợp lệ / gán giá trị mặc định
                        if (input.type === 'text' || input.tagName === 'TEXTAREA') {
                            if (input.id === 'char-color-text') input.value = 'Màu_hồng_anh_đào';
                            else if (input.id === 'char-ability') input.value = 'Năng_lực_thao_túng_ánh_sáng';
                            else input.value = ''; 
                        }
                        else if (input.type === 'color') {
                            input.value = '#FFB6C1';
                        }
                    }
                });
                updateUIState();
                try { colorPicker.value = colorText.value; } catch (err) {}
                setTimeout(() => { textareas.forEach(ta => autoResizeTextarea(ta)); }, 10);
            };

            const saveAutoSave = () => localStorage.setItem(AUTOSAVE_KEY, JSON.stringify(getCurrentFormData()));
            const debouncedAutoSave = () => { clearTimeout(saveTimeout); saveTimeout = setTimeout(saveAutoSave, 500); };

            const loadAutoSave = () => {
                const autoSavedData = localStorage.getItem(AUTOSAVE_KEY);
                if (autoSavedData) {
                    populateForm(JSON.parse(autoSavedData));
                } else {
                    updateUIState();
                }
            };

            // --- Tăng cường phục hồi dữ liệu (Tương thích nhiều phiên bản cũ) ---
            const rescueOldData = () => {
                let rescuedCount = 0;
                let currentProfiles = JSON.parse(localStorage.getItem(PROFILE_STORAGE_KEY) || '{}');

                // Phục hồi Profiles
                ['magicalGirl_ProfileManager', 'magicalGirl_Profiles_v4', 'magicalGirl_ProfileManager_v2'].forEach(key => {
                    const oldProfilesStr = localStorage.getItem(key);
                    if (oldProfilesStr) {
                        try {
                            const oldProfiles = JSON.parse(oldProfilesStr);
                            currentProfiles = { ...oldProfiles, ...currentProfiles }; // Dữ liệu mới ghi đè dữ liệu cũ
                            rescuedCount++;
                        } catch(e){}
                    }
                });
                if (Object.keys(currentProfiles).length > 0) {
                    localStorage.setItem(PROFILE_STORAGE_KEY, JSON.stringify(currentProfiles));
                }

                // Phục hồi AutoSave
                if (!localStorage.getItem(AUTOSAVE_KEY)) {
                    for (const key of ['magicalGirl_AutoSave_v2', 'magicalGirl_AutoSave_v4', 'magicalGirl_AutoSave']) {
                        const oldAuto = localStorage.getItem(key);
                        if (oldAuto) {
                            localStorage.setItem(AUTOSAVE_KEY, oldAuto);
                            populateForm(JSON.parse(oldAuto));
                            rescuedCount++;
                            break;
                        }
                    }
                }
                if (rescuedCount > 0) console.log("Đã phục hồi dữ liệu cũ thành công.");
            };

            const getProfiles = () => JSON.parse(localStorage.getItem(PROFILE_STORAGE_KEY)) || {};
            const saveProfiles = (profiles) => localStorage.setItem(PROFILE_STORAGE_KEY, JSON.stringify(profiles));

            const populateDropdown = () => {
                const profiles = getProfiles();
                const profileNames = Object.keys(profiles);

                profileSelect.innerHTML = '';
                if (profileNames.length === 0) {
                    profileSelect.innerHTML = '<option value="">-- Chưa_có_bản_lưu_nào --</option>';
                    loadProfileBtn.disabled = true; deleteProfileBtn.disabled = true; exportProfilesBtn.disabled = true; 
                } else {
                    profileSelect.innerHTML = '<option value="">-- Chọn_bản_lưu --</option>';
                    profileNames.sort().forEach(name => {
                        const option = document.createElement('option');
                        option.value = name; option.textContent = name;
                        profileSelect.appendChild(option);
                    });
                    loadProfileBtn.disabled = false; deleteProfileBtn.disabled = false; exportProfilesBtn.disabled = false;
                }
            };

            // Trình lắng nghe sự kiện
            form.addEventListener('input', debouncedAutoSave);
            colorPicker.addEventListener('input', () => { colorText.value = colorPicker.value; debouncedAutoSave(); });
            colorText.addEventListener('input', () => { try { colorPicker.value = colorText.value; } catch (err) {} debouncedAutoSave(); });
            personalityRadios.forEach(radio => radio.addEventListener('change', () => { updateUIState(); debouncedAutoSave(); }));

            saveProfileBtn.addEventListener('click', () => {
                const defaultName = document.getElementById('char-name').value || 'Bản_lưu_chưa_đặt_tên';
                const profileName = prompt('Vui lòng nhập tên bản lưu:', defaultName);
                if (profileName && profileName.trim() !== '') {
                    const profiles = getProfiles();
                    profiles[profileName.trim()] = getCurrentFormData();
                    saveProfiles(profiles); populateDropdown(); profileSelect.value = profileName.trim();
                    showNotification(`Lưu_thành_công: "${profileName.trim()}"`);
                }
            });

            loadProfileBtn.addEventListener('click', () => {
                const selectedName = profileSelect.value;
                if (selectedName && getProfiles()[selectedName]) {
                    populateForm(getProfiles()[selectedName]);
                    debouncedAutoSave();
                    showNotification(`Đã_tải: "${selectedName}"`);
                } else { showNotification('Vui lòng chọn bản lưu trước', 'var(--error-color)'); }
            });

            deleteProfileBtn.addEventListener('click', () => {
                const selectedName = profileSelect.value;
                if (selectedName && confirm(`Bạn có chắc chắn muốn xóa vĩnh viễn bản lưu "${selectedName}" không?`)) {
                    const profiles = getProfiles();
                    delete profiles[selectedName];
                    saveProfiles(profiles); populateDropdown();
                    showNotification(`Đã_xóa: "${selectedName}"`);
                }
            });

            exportProfilesBtn.addEventListener('click', () => {
                const profiles = getProfiles();
                if (Object.keys(profiles).length === 0) return;
                const a = document.createElement('a');
                a.href = URL.createObjectURL(new Blob([JSON.stringify(profiles, null, 2)], {type: 'application/json'}));
                a.download = `magical-girl-profiles-${Date.now()}.json`;
                a.click(); URL.revokeObjectURL(a.href);
                showNotification('Đã_xuất_bản_lưu');
            });

            importProfilesBtn.addEventListener('click', () => importFileInput.click());
            importFileInput.addEventListener('change', (event) => {
                const file = event.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        const imported = JSON.parse(e.target.result);
                        let current = getProfiles(), count = 0;
                        for (const name in imported) {
                            if (!current[name] || confirm(`Ghi đè bản lưu trùng tên "${name}" không?`)) { current[name] = imported[name]; count++; }
                        }
                        saveProfiles(current); populateDropdown();
                        showNotification(`Đã nhập ${count} bản lưu`);
                    } catch (error) { showNotification('Nhập thất bại: Sai định dạng file', 'var(--error-color)'); }
                    importFileInput.value = '';
                };
                reader.readAsText(file);
            });

            resetFormBtn.addEventListener('click', () => {
                if (confirm('Bạn có chắc chắn muốn làm trống toàn bộ nội dung hiện tại không?')) {
                    form.reset();
                    document.getElementById('state-good').checked = true;
                    document.getElementById('char-color-text').value = 'Màu_hồng_anh_đào';
                    document.getElementById('char-color-picker').value = '#FFB6C1';
                    document.getElementById('char-ability').value = 'Năng_lực_thao_túng_ánh_sáng';
                    updateUIState(); debouncedAutoSave();
                    showNotification('Đã_đặt_lại_biểu_mẫu');
                }
            });

            generateBtn.addEventListener('click', () => {
                saveAutoSave();
                generateBtn.disabled = true;
                generateBtn.innerHTML = `<i class="fa-solid fa-spinner fa-spin"></i> <span>Đang_ký_kết...</span>`;
                notification.style.opacity = '0';

                const data = getCurrentFormData();
                const formatValue = (value, placeholder = '[AI_vui_lòng_điền]') => {
                    const trimmedValue = (value || "").trim();
                    return trimmedValue === '' ? placeholder : `"${trimmedValue}"`;
                };

                // Loại bỏ mẫu YAML trạng thái mở màn
                const yamlString = `<init_data>
\`\`\`yaml
# Chỉ_lệnh_nhiệm_vụ_AI: Phân tích hồ sơ tạo nhân vật của người dùng dưới đây, tạo lời chào đầu và khởi tạo tất cả các biến.
# Đối với các trường có giá trị "[AI_vui_lòng_điền]", bạn [BẮT_BUỘC] phải dựa trên thiết lập hiện có để điền vào một cách hợp lý và phong phú.

Hồ_sơ_tạo_nhân_vật:
  Nhân_cách_cốt_lõi:
    Họ_tên: ${formatValue(data['char-name'], '')} 
    Sở_thích_tình_dục_ban_đầu: ${formatValue(data['char-kinks'], 'Không')} 
    Trạng_thái_nhân_cách: "${data['personality-state']}"
    Đặc_điểm_tính_cách: ${formatValue(data['char-traits'])}
    Chủ_nhân: ${data['personality-state'] === 'Sa_ngã' ? formatValue(data['char-master']) : 'Không'}
  Khế_ước_ma_pháp:
    Loại_sử_ma_đồng_hành: ${formatValue(data['familiar-type'])}
    Tính_cách_sử_ma_đồng_hành: ${formatValue(data['familiar-personality'])}
    Quan_hệ_sử_ma_và_nhân_vật_chính: ${formatValue(data['familiar-relationship'])}
    Màu_đại_diện: "${data['char-color-text']}"
    Năng_lực_cốt_lõi: "${data['char-ability']}"
  Ngoại_hình_tóm_tắt:
    Từ_khóa_ngoại_hình: ${formatValue(data['appearance-keywords'])}
    Từ_khóa_cơ_thể: ${formatValue(data['body-keywords'])}
  Thiết_lập_bổ_sung: ${formatValue(data['extra-notes'], 'Không')}
\`\`\`
</init_data>`;

                setTimeout(() => {
                    try {
                        const inputArea = window.parent.document.querySelector('#send_textarea');
                        const sendButton = window.parent.document.querySelector('#send_but');
                        if (inputArea && sendButton) {
                            inputArea.value = yamlString;
                            inputArea.dispatchEvent(new Event('input', { bubbles: true }));
                            sendButton.click();
                            showNotification('Khế_ước_đã_gửi! Đang chờ AI phản hồi...');
                            generateBtn.innerHTML = `<i class="fa-solid fa-check"></i> <span>Khế_ước_đã_gửi</span>`;
                        } else { throw new Error('SillyTavern UI not found.'); }
                    } catch (error) {
                        console.error('Error sending message:', error);
                        generateBtn.innerHTML = `<i class="fa-solid fa-xmark"></i> <span>Gửi_thất_bại</span>`;
                        navigator.clipboard.writeText(yamlString).then(() => {
                            showNotification('Gửi tự động thất bại! Đã sao chép vào khay nhớ tạm.', 'var(--error-color)');
                            alert('Gửi tự động thất bại! Thông tin nhân vật đã được sao chép vào khay nhớ tạm, vui lòng dán và gửi thủ công.');
                        });
                    }
                    setTimeout(() => {
                        generateBtn.disabled = false;
                        generateBtn.innerHTML = initialButtonHTML;
                    }, 4000);
                }, 400);
            });

            // Khởi tạo
            rescueOldData(); 
            populateDropdown(); 
            loadAutoSave(); 
        });
    </script>
</body>
</html>
