<script>
    let lastActiveTabId = 'panel-character';
    let _gmSnapshot = null;
    let _currentMvuData = null;

    // 简化的 DOM 更新函数
    function updateDOM(fromNode, toNode) { if (!fromNode || !toNode) return; const fromAttrs = fromNode.attributes, toAttrs = toNode.attributes; for (const attr of toAttrs) { if (fromNode.getAttribute(attr.name) !== attr.value) fromNode.setAttribute(attr.name, attr.value); } for (const attr of fromAttrs) { if (!toNode.hasAttribute(attr.name)) fromNode.removeAttribute(attr.name); } const fromChildren = Array.from(fromNode.childNodes), toChildren = Array.from(toNode.childNodes); for (let i = 0; i < Math.max(fromChildren.length, toChildren.length); i++) { const fromChild = fromChildren[i], toChild = toChildren[i]; if (!toChild) { fromNode.removeChild(fromChild); } else if (!fromChild) { fromNode.appendChild(toChild.cloneNode(true)); } else if (fromChild.nodeType !== toChild.nodeType || fromChild.tagName !== toChild.tagName) { fromNode.replaceChild(toChild.cloneNode(true), fromChild); } else if (fromChild.nodeType === Node.TEXT_NODE) { if (fromChild.textContent !== toChild.textContent) { fromChild.textContent = toChild.textContent; } } else if (fromChild.nodeType === Node.ELEMENT_NODE) { updateDOM(fromChild, toChild); } } }

    const getValue = (data, path, defaultValue = null) => { const value = path.split('.').reduce((acc, part) => acc && acc[part], data); return (value === undefined || value === null) ? defaultValue : value; };
    const getDeep = (obj, path, def) => path.split('.').reduce((acc, part) => acc && acc[part], obj) ?? def;

    const createDetailItem = (label, value, iconClass = null) => { if (!value || value === '待设定' || value === '无') return ''; const iconHtml = iconClass ? `<i class="fa-solid ${iconClass}"></i>` : ''; return `<div class='item-label'>${iconHtml}${label}</div><div class='item-value'>${value}</div>`; };
    const createRichItem = (label, mainText, subHtml, iconClass = null) => {
        if (!mainText || mainText === '待设定' || mainText === '无') return '';
        const iconHtml = iconClass ? `<i class="fa-solid ${iconClass}"></i>` : '';
        const subContent = subHtml ? `<div class='rich-sub-text'>${subHtml}</div>` : '';
        return `
        <div class='item-label'>${iconHtml}${label}</div>
        <div class='rich-value-box'>
            <div class='rich-main-text'>${mainText}</div>
            ${subContent}
        </div>`;
    };

    const TOOLTIP_DEFINITIONS = {
