        if (kinkEntries.length === 0) {
            kinkHtml = `<div style='grid-column: 1/-1; text-align:center; color:var(--text-secondary); padding:10px;'>暂无性癖觉醒</div>`;
        } else {
            kinkHtml = kinkEntries.map(([key, val]) => {
                const exp = val.经验 || val.经验值 || 0;
                const level = val.等级 || 0;
                const levelInfo = KINK_LEVELS[level] || KINK_LEVELS[0];
                const isMax = levelInfo.xp_needed === Infinity;
                const rankClass = `rank-${Math.min(level, 4)}`;
                const prevXp = level > 0 ? KINK_LEVELS[level - 1].xp_needed : 0;

                let progressPercent = 0;
                if (isMax) { progressPercent = 100; } 
                else { progressPercent = Math.max(0, Math.min(100, ((exp - prevXp) / (levelInfo.xp_needed - prevXp)) * 100)); }

                let xpDisplayHtml = isMax 
                    ? `<span class="kink-xp is-max">${exp} <small>MAX</small></span>`
                    : `<span class="kink-xp">${exp} <small>/ ${levelInfo.xp_needed}</small></span>`;
                const barColor = isMax ? 'var(--ultimate-color)' : 'var(--accent-color)';

                return `
                <div style="grid-column: 1/-1; margin-bottom:6px;">
                    <div class="kink-row">
                        <div class="kink-name ${rankClass}">
                            <i class="fa-solid ${levelInfo.icon} rank-icon"></i>
                            <span>${key} <span style="font-size:0.8em; opacity:0.8; font-weight:normal;">Lv.${level}</span></span>
                        </div>
                        <div>${xpDisplayHtml}</div>
                    </div>
                    <div class="kink-progress-container">
                        <div class="progress-fill" style="width: ${progressPercent}%; background: ${barColor}; box-shadow: 0 0 10px ${barColor};"></div>
                    </div>
                </div>`;
            }).join('');
        }

        const getListValues = (path) => {
            const raw = getValue(data, path, {});
            if (Array.isArray(raw)) return raw;
            if (typeof raw === 'object' && raw !== null) return Object.values(raw);
            return [];
        };

        const bossesList = getListValues('记录.已击败的Boss');
        let bossesHtml = bossesList.filter(b => b !== '$__META_EXTENSIBLE__$').map(boss => { 
            const bossName = (typeof boss === 'object' ? boss.名称 : boss) || '未知'; 
            const tagsArray = (typeof boss === 'object' ? boss.核心主题 : []) || []; 
            const result = (typeof boss === 'object' ? boss.结果 : 'WIN') || 'WIN';
            const tagsText = (tagsArray.length > 0) ? `<div class='label'>核心主题:</div><div class='value'>${tagsArray.join(', ')}</div>` : '无特殊主题'; 

            let icon, styleClass;
            if (result === 'LOSE') {
                icon = 'fa-heart-crack'; styleClass = 'color: var(--combat-color); opacity: 0.8;';
            } else {
                icon = 'fa-skull-crossbones'; styleClass = 'color: var(--text-color);';
            }
            return `<span class='has-tooltip' style='display:inline-block; margin-right:8px; ${styleClass}'><span class=\"tooltip-trigger\"><i class=\"fa-solid ${icon}\"></i> ${bossName}</span><span class='custom-tooltip'>${tagsText}<br><span style='font-size:0.8em; opacity:0.6'>${result === 'LOSE' ? '败北记录' : '讨伐成功'}</span></span></span>`; 
        }).join(' <br>');

        const childrenList = getListValues('记录.诞下的子嗣');
        const validChildren = childrenList.filter(c => typeof c === 'object' && c !== null);
        const childrenDisplayHtml = (validChildren.length > 0) ? validChildren.map(child => {
            const childName = child.名称 || '新生儿'; 
            const childSource = child.来源 || '未知'; 
            const childFeatures = child.特征 || '无'; 
            const tooltipContent = `<div class='label'>来源:</div><div class='value'>${childSource}</div><div class='label'>特征:</div><div class='value'>${childFeatures}</div>`; 
            return `<span class='has-tooltip'><span class=\"tooltip-trigger\">👼 ${childName}</span><span class='custom-tooltip'>${tooltipContent}</span></span>`; 
        }).join(' <br>') : '';

        const recordsHeader = (personality === '善良') ? '讨伐记录' : '战利品';
        const recordsIcon = (personality === '善良') ? 'fa-skull-crossbones' : 'fa-gem';
        const childrenLabel = (personality === '善良') ? '诞下子嗣' : '我的作品';

        return `<div class=\"details-grid\">
            <div class='details-section-header'><i class=\"fa-solid fa-arrow-trend-up\"></i> <b>性癖开发</b></div>
            ${kinkHtml}
            <div class='details-section-header'><i class=\"fa-solid fa-scroll\"></i> <b>冒险记录</b></div>
            ${createDetailItem('总高潮次数', getValue(data, '主角.快感状态.总高潮次数', 0), 'fa-wave-square')}
            ${createDetailItem('总战败', getValue(data, '记录.总战败次数', 0), 'fa-heart-crack')}
            ${createDetailItem(recordsHeader, bossesHtml, recordsIcon)}
            ${createDetailItem(childrenLabel, childrenDisplayHtml, 'fa-baby')} 
        </div>`;
    };

    // --- 心跳共鸣条渲染 (EKG) ---
    const renderEKGMonitor = (data) => {
        const current = getValue(data, '主角.快感状态.快感值', 0);
        const threshold = getValue(data, '主角.快感状态.高潮阈值', 100);
        const ratio = Math.min(1, current / threshold); 
        const percent = ratio * 100;
        let beatClass = 'beating'; let fillClass = '';

        if (current >= threshold) { beatClass = 'beating-fast'; fillClass = 'critical'; }
        else if (ratio >= 0.7) { beatClass = 'beating-fast'; }

        return `
        <div class="ekg-wrapper">
            <div class="ekg-heart-box"><i class="fa-solid fa-heart ekg-icon ${beatClass}"></i></div>
            <div style="display:flex; flex-direction:column; gap:4px; width:100%;">
                <div style="display:flex; justify-content:space-between; font-size:0.8em; color:var(--text-secondary); padding:0 2px;">
                    <span>PLEASURE</span><span>${Math.round(percent)}%</span>
                </div>
                <div class="ekg-bar-container"><div class="ekg-bar-fill ${fillClass}" style="width: ${percent}%"></div></div>
            </div>
            <div class="ekg-data">${Math.round(current)}</div>
        </div>`;
    };

    // --- 主面板渲染逻辑 ---
    const renderStatusPanel = (data) => {
        if (!data || !getValue(data, '系统状态.主角创建完毕')) return `<div class='status-card' style='text-align:center; padding:20px;'>等待连接...</div>`;

        // 1. 变量提取
        const personality = getValue(data, '主角.核心状态.人格状态', '善良');
        const isFallen = personality === '堕落';
        const corruption = getValue(data, '主角.快感状态.污染度', 0);
        const levelState = getValue(data, '进程.阶段', '幕间休息');

        // 2. 标题与状态判定
        const isTransformed = getValue(data, '主角.核心状态.变身状态', false);
        const magicName = getValue(data, '主角.基本信息.魔法少女名');
        const realName = getValue(data, '主角.基本信息.姓名');
        const currentName = (isTransformed && magicName) ? magicName : (realName || '主角');
        const prefixText = isFallen ? '堕落魔法少女' : '魔法少女';

        const currentEvents = getValue(data, '系统状态.待处理事件', {});
        const isCorrupting = currentEvents['魔法少女恶堕'] || currentEvents['堕落临界点'];
        const headerTitle = `<span class='${isCorrupting ? 'corrupt-active' : ''}'>${prefixText} ${currentName}</span>`;

        // 3. UI 标签定义
        const hpLabel = isFallen ? '耐久' : '体力';
        const mpLabel = isFallen ? '欲力' : '魔力';
        const corruptionLabel = isFallen ? '恩宠' : '侵蚀';
        const corruptionIcon = isFallen ? 'fa-crown' : 'fa-biohazard';
        const ultimateLabel = isFallen ? '欲望充能' : '意志充能';
        const ultimateIcon = isFallen ? 'fa-moon' : 'fa-sun';

        const tab1Label = isFallen ? '烙印' : '档案';
        const tab2Label = isFallen ? '肉体' : '身体';
        const tab3Label = isFallen ? '战果' : '记录';
        const bodyTabIcon = isFallen ? 'fa-venus-mars' : 'fa-dna';
        const recordsTabIcon = isFallen ? 'fa-trophy' : 'fa-book-medical';

        // 4. 动态主题
        let themeClass = 'theme-pure';
        if (isFallen) { themeClass = 'theme-fallen-core'; }
        else if (corruption > 65) { themeClass = 'theme-eroded'; }
        let cardClass = `status-card ${themeClass}`;
        if (getValue(data, '主角.核心状态.净化之力', 0) >= 100 || getValue(data, '主角.核心状态.污秽魔力', 0) >= 100) cardClass += ' state-ultimate-ready';
        else if (getValue(data, '主角.核心状态.体力值.当前', 100) <= 35) cardClass += ' state-danger';

        // 5. 上下文区域 (战斗/幕间)
        let contextualHtml = '';
        if (levelState === '战斗准备' || levelState === '战斗回合') {
            const bossName = getValue(data, '世界.当前关卡.名称', '未知');
            let statusDisplay;
            if (levelState === '战斗准备') {
                const bossThemes = getValue(data, '世界.当前关卡.核心主题', []).filter(t => t !== '$__META_EXTENSIBLE__$');
                let themesHtml = (bossThemes.length > 0) ? `<div class='boss-themes'><i class='fa-solid fa-tags'></i> ${bossThemes.join(' / ')}</div>` : '';
                statusDisplay = `<div class="intermission-status"><div style="font-size:0.8em; color:var(--text-secondary)">Target Acquired</div><div class='main-status' style='color: var(--combat-color);'>${bossName}</div>${themesHtml}</div>`;
            } else { // 战斗回合
                const bossToughness = getValue(data, '世界.当前关卡.Boss韧性值', null);
                let bossHealthBar = '';

                // 威胁等级
                const threatLv = getValue(data, '世界.威胁等级', 1);
                const threatConfig = isFallen 
                    ? { 1: { t: '玩物', c: '#a8d8ea' }, 2: { t: '猎物', c: '#bb9af7' }, 3: { t: '强敌', c: '#f7768e' } }
                    : { 1: { t: '骚扰者', c: '#9ece6a' }, 2: { t: '侵犯者', c: '#e0af68' }, 3: { t: '支配者', c: '#f87171' } };
                const tInfo = threatConfig[threatLv] || { t: '未知威胁', c: '#787c99' };
                const threatHtml = `<span style="color:${tInfo.c}; font-weight:bold; padding:2px 6px; background:rgba(0,0,0,0.2); border-radius:4px; margin-left:6px; font-size:0.8em;">Lv.${threatLv} ${tInfo.t}</span>`;

                if (bossToughness !== null) {
                    const bossHpPct = Math.max(0, Math.min(100, bossToughness));
                    bossHealthBar = `
                    <div class='progress-item'>
                        <div class='progress-label'><span><i class='fa-solid fa-shield-virus'></i> <span>韧性 (Boss)</span></span><span class='progress-value'>${bossToughness}/100</span></div>
                        <div class='progress-bar' style="position:relative; overflow:visible; background:rgba(0,0,0,0.6);">
                            <div class="boss-phase-marker" style="left: 30%;" data-phase="P3"></div>
                            <div class="boss-phase-marker" style="left: 70%;" data-phase="P2"></div>
                            <div class='progress-fill' style='width: ${bossHpPct}%; background: var(--combat-color); position:relative; z-index:1;'></div>
                        </div>
                    </div>`;
                }
                const posture = getValue(data, '主角.核心状态.当前战斗姿态', '战斗中');
                const postureMap = isFallen ? { '战斗中': '狩猎中', '劣势': '享乐中' } : { '战斗中': '戦闘中', '劣势': '劣勢' };
                const bossState = getValue(data, '世界.当前关卡.Boss状态', '完好');
                const bossThemes = getValue(data, '世界.当前关卡.核心主题', []).filter(t => t !== '$__META_EXTENSIBLE__$');
                const bossThemeHtml = (bossThemes.length > 0) ? `<div class='side-theme'>${bossThemes.join(' / ')}</div>` : '';

                let combatLogHtml = '';
                const lastCombatLog = getValue(data, '主角.战斗临时.当前战斗日志', '无');
                if (lastCombatLog && lastCombatLog !== '无') { 
                    const parts = lastCombatLog.split('|'); 
                    const resultText = parts[0] || '检定'; 
                    const isFailure = resultText.includes('失败') || resultText.includes('纠缠'); 
                    combatLogHtml = `<div class=\"combat-log-display\"><div><b>战报: <span class=\"${isFailure ? 'log-failure' : 'log-success'}\">${resultText.replace('结果:','')}</span></b></div><small style=\"opacity: 0.8;\">${parts.slice(1).join(' | ')}</small></div>`; 
                }
                statusDisplay = `<div class='battle-status-grid'><div class='status-side player-side'><div class='side-label'>Player</div><div class='side-main'>${currentName}</div><div class='side-status-container'><span class='side-status-tag'>${postureMap[posture] || posture}</span></div></div><div class='status-side enemy-side'><div class='side-label'>Enemy ${threatHtml}</div><div class='side-main'>${bossName}</div><div class='side-status-container'><span class='side-status-tag' style='background:var(--combat-color)'>${bossState}</span></div>${bossThemeHtml}</div></div>${bossHealthBar}${combatLogHtml}`;
            }
            contextualHtml = `<div class=\"context-box\">${statusDisplay}</div>`;
        } else {
            // 幕间事件处理
            const eventName = getValue(data, '世界.幕间H事件.名称', '无');
            if (eventName && eventName !== '无') {
                const eventThemes = getValue(data, '世界.幕间H事件.核心主题', []).filter(t => t !== '$__META_EXTENSIBLE__$').join(' / ');
                contextualHtml = `
                <div class=\"context-box intermission-status\" style=\"border-left: 4px solid var(--pleasure-color); background: linear-gradient(90deg, rgba(233,30,99,0.1), transparent);\">
                    <div style=\"color:var(--pleasure-color); font-weight:bold; font-size:0.9em; margin-bottom:5px;\">
                        <i class=\"fa-solid fa-triangle-exclamation\"></i> 幕间H事件
                    </div>
                    <div class='main-status' style=\"font-size:1.2em; line-height:1.3;\">${eventName}</div>
                    <div class='sub-status' style=\"color:var(--text-secondary); margin-top:5px; font-size:0.85em;\"> <i class=\"fa-solid fa-tags\"></i> ${eventThemes} </div>
                </div>`;
            } else {
                const stateText = { '幕间休息': (isFallen ? '🍷 间歇' : '☕ 幕间'), '终结回合': '✨ 终结时刻', '战斗胜利': '🏆 战斗胜利', '战斗败北': '💔 力尽败北', '战后处理': '🧹战后清理' }[levelState] || levelState;
                contextualHtml = `<div class=\"context-box intermission-status\"><div class='main-status'>${stateText}</div><div class='sub-status'>${getValue(data, '主角.生理状态.当前生理动态')}</div></div>`;
            }
        }

        const ekgMonitorHtml = (typeof renderEKGMonitor === 'function') ? renderEKGMonitor(data) : '';

        const progressHtml = `<div class=\"progress-stack\">
            <div class='stack-header'>基础资源</div>
            ${renderProgressItem({ path: '主角.核心状态.体力值.当前', label: hpLabel, options: { icon: 'fa-solid fa-heart', color: 'var(--hp-color)', max: getValue(data, '主角.核心状态.体力值.最大', 100) } }, data, isFallen)}
            ${renderProgressItem({ path: '主角.核心状态.魔力值.当前', label: mpLabel, options: { icon: 'fa-solid fa-wand-magic-sparkles', color: 'var(--mp-color)', max: getValue(data, '主角.核心状态.魔力值.最大', 100) } }, data, isFallen)}
            <div class='stack-header'>精神与感官</div>
            ${ekgMonitorHtml}
            ${renderProgressItem({ path: '主角.快感状态.污染度', label: corruptionLabel, options: { icon: `fa-solid ${corruptionIcon}`, color: 'var(--corruption-color)' } }, data, isFallen)}
            <div class='stack-header'>必杀技</div>
            <div class='progress-item'>${renderProgressItem({ path: isFallen ? '主角.核心状态.污秽魔力' : '主角.核心状态.净化之力', label: ultimateLabel, options: { icon: `fa-solid ${ultimateIcon}`, color: 'var(--ultimate-color)' } }, data, isFallen)}</div>
        </div>`;

        const tabbedHtml = `
            <div class=\"tab-container\">
                <button class=\"tab-btn\" data-target=\"panel-character\"><i class=\"fa-solid fa-address-card\"></i> ${tab1Label}</button>
                <button class=\"tab-btn\" data-target=\"panel-body\"><i class=\"fa-solid ${bodyTabIcon}\"></i> ${tab2Label}</button>
                <button class=\"tab-btn\" data-target=\"panel-records\"><i class=\"fa-solid ${recordsTabIcon}\"></i> ${tab3Label}</button>
            </div>
            <div class=\"content-container\">
                <div id=\"panel-character\" class=\"tab-content\">${renderCharacterInfo(data, personality)}</div>
                <div id=\"panel-body\" class=\"tab-content\">${renderBodyStatus(data)}</div>
                <div id=\"panel-records\" class=\"tab-content\">${renderRecords(data, personality)}</div>
            </div>`;

        return `<div class='${cardClass}'>
            <div class=\"panel-left\">
                <div class=\"card-header\"><h2>${headerTitle}</h2>                   </div>
                ${contextualHtml}
                ${progressHtml}
            </div>
            <div class=\"panel-right\">${tabbedHtml}</div>
        </div>`;
    };

    const renderPanelWithData = (stat_data) => {
        if (typeof hideDynamicTooltip === 'function') {
            hideDynamicTooltip(); 
            const oldTooltips = document.querySelectorAll('.custom-tooltip-dynamic');
            oldTooltips.forEach(el => el.remove());
        }
        const container = document.getElementById('status-card-container');
        if (!container) return;
        try {
            const newHTML = renderStatusPanel(stat_data);
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = newHTML;
            const newContent = tempDiv.firstChild;
            if (newContent && newContent.querySelector) {
                const newActiveButton = newContent.querySelector(`[data-target="${lastActiveTabId}"]`);
                if (newActiveButton) newActiveButton.classList.add('active');
                const newActivePanel = newContent.querySelector(`#${lastActiveTabId}`);
                if (newActivePanel) newActivePanel.classList.add('active');
            }
            if (container.firstChild) { updateDOM(container.firstChild, newContent); } 
            else { if(newContent) container.appendChild(newContent); }
        } catch (error) {console.error('Status Panel Error:', error); container.innerHTML = `<div class='status-card' style='color:var(--combat-color);'>渲染出错: ${error.message}</div>`; } 
    };

    function getMvuInstance() { try { return window.Mvu || (window.parent && window.parent.Mvu) || (window.top && window.top.Mvu) || null; } catch (e) { return null; } }

    // --- Tooltip 悬浮窗逻辑 ---
    const setupTooltips = () => {
        let activeTooltip = null;
        const showTip = (target) => {
            const tooltip = target.querySelector('.custom-tooltip');
            if (!tooltip) return;
            tooltip.classList.add('active');
            activeTooltip = tooltip;
            const targetRect = target.getBoundingClientRect();
            const tipRect = tooltip.getBoundingClientRect();
            let top = targetRect.top + (targetRect.height / 2) - (tipRect.height / 2);
            let left = targetRect.right + 15; 
            if (top + tipRect.height > window.innerHeight - 10) { top = window.innerHeight - tipRect.height - 10; }
            if (top < 10) top = 10;
            if (left + tipRect.width > window.innerWidth - 10) { left = targetRect.left - tipRect.width - 15; }
            tooltip.style.top = top + 'px';
            tooltip.style.left = left + 'px';
        };
        const hideTip = () => { if (activeTooltip) { activeTooltip.classList.remove('active'); activeTooltip = null; } };
        document.addEventListener('mouseover', (e) => { const trigger = e.target.closest('.has-tooltip'); if (trigger) showTip(trigger); });
        document.addEventListener('mouseout', (e) => { const trigger = e.target.closest('.has-tooltip'); if (trigger) hideTip(); });
        window.addEventListener('scroll', hideTip, true);
    };

    // 初始化
    setupTooltips();
    const init = () => {
        const Mvu = window.Mvu || (window.parent && window.parent.Mvu) || (window.top && window.top.Mvu);
        if (Mvu && Mvu.events) {
            console.log("[PC Status] MVU found, registering native listeners.");
            document.addEventListener(Mvu.events.VARIABLE_UPDATE_ENDED, (e) => {
                if (e.detail && e.detail.stat_data) { renderPanelWithData(e.detail.stat_data); }
            });
            (async () => { 
                try { 
                    if (typeof getChatMessages !== 'undefined') {
                        const msgs = await getChatMessages(getCurrentMessageId());
                        const data = msgs[0]?.data?.stat_data || Mvu.getMvuData({type:'message', message_id:-1})?.stat_data;
                        renderPanelWithData(data);
                    }
                } catch (e) { console.warn("[PC Status] Initial fetch failed.", e); } 
            })();
            const container = document.getElementById('status-card-container');
            if (container) {
                container.addEventListener('click', (event) => {
                    const button = event.target.closest('.tab-btn');
                    if (!button || button.classList.contains('active')) return;
                    const targetPanelId = button.dataset.target;
                    const targetPanel = container.querySelector(`#${targetPanelId}`);
                    if (!targetPanel) return;
                    container.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
                    container.querySelectorAll('.tab-content').forEach(panel => panel.classList.remove('active'));
                    button.classList.add('active');
                    targetPanel.classList.add('active');
                    lastActiveTabId = targetPanelId;
                });
            }
        } else {
            setTimeout(init, 500);
        }
    };

    if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', init); } else { init(); }

    // --- GM 主渲染逻辑 (整合版) ---
    window.toggleGM = () => {
        const p = document.getElementById('gm-panel');
        if (p) {
            if (!p.classList.contains('show')) {
                p.style.display = 'flex'; 
                requestAnimationFrame(() => {
                    p.classList.add('show');
                    window.renderGM();
                    if(_currentMvuData) {
                        _gmSnapshot = JSON.parse(JSON.stringify(_currentMvuData));
                        showToast("Snapshot created", "#save-status");
                    }
                });
            } else {
                p.classList.remove('show');
                setTimeout(() => p.style.display = 'none', 250);
            }
        }
    };

    window.toggleGMMaximize = () => {
        const p = document.getElementById('gm-panel');
        const icon = document.getElementById('gm-max-icon');
        if (p) {
            p.classList.toggle('maximized');
            icon.className = p.classList.contains('maximized') ? "fa-regular fa-clone" : "fa-regular fa-square";
        }
    };

    window.switchGmTab = (btn, targetId) => {
        document.querySelectorAll('.gm-tab').forEach(t => t.classList.remove('active'));
        btn.classList.add('active');
        document.querySelectorAll('.gm-content').forEach(c => c.classList.remove('active'));
        document.getElementById(targetId).classList.add('active');
    };

    const showToast = (msg, selector) => {
        const el = document.querySelector(selector);
        if(el) { el.innerText = msg; el.style.opacity = 1; setTimeout(() => el.style.opacity = 0, 2000); }
    };

    const setInp = (id, val) => {
        const el = document.getElementById(id);
        if(el && document.activeElement !== el) el.value = (typeof val === 'number') ? Math.round(val) : val;
    };
    const setTxt = (id, val) => { const el = document.getElementById(id); if(el) el.innerText = val; };

    window.gm_update = async (path, value, mode = 'set') => {
        try {
            const Mvu = window.Mvu || window.parent?.Mvu || window.top?.Mvu;
            if (!Mvu) return;
            const mvuData = Mvu.getMvuData({ type: 'message', message_id: -1 });
            if (!mvuData) return;
            if (typeof _ !== 'undefined' && _.set) {
                if (mode === 'remove') _.unset(mvuData, path);
                else if (mode === 'add') { const old = _.get(mvuData, path) || 0; _.set(mvuData, path, Number(old) + Number(value)); }
                else _.set(mvuData, path, value);
            }
            await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: -1 });
            const cleanData = JSON.parse(JSON.stringify(mvuData.stat_data || mvuData));
            document.dispatchEvent(new CustomEvent(Mvu.events.VARIABLE_UPDATE_ENDED, { detail: { stat_data: cleanData }, bubbles: true }));
            setTimeout(renderGM, 50);
        } catch (e) { console.error("[GM Update]", e); }
    };

// --- GM核心渲染逻辑 ---
    window.renderGM = async () => {
        try {
            const Mvu = window.Mvu || window.parent?.Mvu || window.top?.Mvu;
            if (!Mvu) return;
            const wrapper = Mvu.getMvuData({ type: 'message', message_id: -1 });
            if (!wrapper) return;
            _currentMvuData = wrapper.stat_data || wrapper;
            const d = _currentMvuData;

            const phase = getDeep(d, '进程.阶段', '幕间休息');
            const isIntermission = (phase === '幕间休息');
            // 将所有带有战斗元素的环节统称为 CombatFlow
            const isCombatFlow = ['战斗准备', '战斗回合', '终结回合', '战斗胜利', '战斗败北', '战后处理'].includes(phase);

            // 1. 场景隔离：控制两大专属模块组的显隐
            document.getElementById('panel-intermission-group').style.display = isIntermission ? 'flex' : 'none';
            document.getElementById('panel-combat-group').style.display = isCombatFlow ? 'block' : 'none';

            setTxt('current-phase-display', phase);
            setInp('phase-selector', phase);

            // 2. 主题注入器：智能切换目标
            const themeSelector = document.getElementById('theme-target-selector');
            if (window._lastRenderedPhase !== phase) {
                // 如果阶段发生变化，自动将注入器的下拉框切换到对应的目标
                themeSelector.value = isCombatFlow ? 'boss' : 'hevent';
                window._lastRenderedPhase = phase;
            }

            // 绑定渲染标签的函数
            window.updateThemeTagsView = () => {
                const target = document.getElementById('theme-target-selector').value;
                const targetPath = target === 'hevent' ? '世界.幕间H事件.核心主题' : '世界.当前关卡.核心主题';
                const themes = getDeep(_currentMvuData, targetPath, []);
                const validThemes = Array.isArray(themes) ? themes.filter(t => t !== '$__META_EXTENSIBLE__$') : [];

                // 视觉色彩区分：粉色是H事件，金色是Boss
                const tagColor = target === 'hevent' ? '#f7768e' : '#e0af68';

                document.getElementById('theme-tags-container').innerHTML = validThemes.map(t => `
                    <div class="theme-tag" style="border-color:${tagColor}; color:${tagColor}; background:rgba(255,255,255,0.05);">
                        ${t} <span class="del" onclick="removeTheme('${targetPath}', '${t}')">×</span>
                    </div>`).join('') || '<span style="opacity:0.5; font-style:italic;">无主题</span>';
            };
            updateThemeTagsView(); // 执行标签渲染

            // 3. 通用数值填充
            setInp('inp-hp', getDeep(d, '主角.核心状态.体力值.当前', 0));
            setInp('inp-mp', getDeep(d, '主角.核心状态.魔力值.当前', 0));
            setInp('inp-pleasure', getDeep(d, '主角.快感状态.快感值', 0));
            setInp('inp-corruption', getDeep(d, '主角.快感状态.污染度', 0));

            setTxt('val-boss-name', getDeep(d, '世界.当前关卡.名称', 'Unknown'));
            setInp('inp-boss-hp', getDeep(d, '世界.当前关卡.Boss韧性值', 0));
            setInp('inp-boss-str', getDeep(d, '世界.当前关卡.Boss基础强度', 0));

            const fame = getDeep(d, '名声.知名度', 0); const rep = getDeep(d, '名声.风评', 0);
            setInp('inp-fame', fame); setInp('range-fame', fame);
            setInp('inp-rep', rep); setInp('range-rep', rep);

            // 4. 事件队列填充
            const events = getDeep(d, '系统状态.待处理事件', {});
            document.getElementById('event-list-container').innerHTML = Object.keys(events).filter(k => k !== '$meta' && k !== '$__META_EXTENSIBLE__$').map(k => `
                <div class="event-item"><span>${k}</span><i class="fa-solid fa-xmark del" onclick="gm_update('stat_data.系统状态.待处理事件.${k}', null, 'remove')"></i></div>
            `).join('') || '<div style="text-align:center; opacity:0.5; padding:4px;">(空)</div>';

            // 5. 幕间面板内部逻辑渲染 (仅当为幕间时才计算以节省性能)
            if (isIntermission) {

                // --- A. 幕间 H事件 逻辑 ---
                const heventName = getDeep(d, '世界.幕间H事件.名称', '无');
                const heventThemes = getDeep(d, '世界.幕间H事件.核心主题', []);
                const cleanThemes = Array.isArray(heventThemes) ? heventThemes.filter(t => t !== '$__META_EXTENSIBLE__$') : [];
                const heventCompleted = getDeep(d, '系统状态.幕间事件完成', true);

                const elStatus = document.getElementById('hevent-status-val');
                const elTheme = document.getElementById('hevent-theme-val');
                const btnReroll = document.getElementById('btn-reroll-hevent');
                const btnTrigger = document.getElementById('btn-trigger-hevent');
                const btnSkip = document.getElementById('btn-skip-hevent');

                elTheme.innerText = cleanThemes.length > 0 ? cleanThemes.join(' / ') : '无';

                if (heventName !== '无') { // 事件进行中
                    elStatus.innerText = `进行中: ${heventName.replace('EVENT：', '')}`;
                    elStatus.style.color = 'var(--pleasure-color)';
                    btnReroll.disabled = true; btnReroll.style.opacity = '0.4';
                    btnTrigger.disabled = true; btnTrigger.style.opacity = '0.4';
                    btnSkip.disabled = false; btnSkip.style.opacity = '1';
                } else if (!heventCompleted && cleanThemes.length > 0) { // 系统已锁定主题等待触发
                    elStatus.innerText = '预锁定 (待AI触发)';
                    elStatus.style.color = '#e0af68';
                    btnReroll.disabled = false; btnReroll.style.opacity = '1';
                    btnTrigger.disabled = false; btnTrigger.querySelector('span').innerText = '强制开始'; btnTrigger.style.opacity = '1';
                    btnSkip.disabled = false; btnSkip.style.opacity = '1';
                } else { // 空闲状态
                    elStatus.innerText = '空闲';
                    elStatus.style.color = 'var(--gm-text)';
                    btnReroll.disabled = false; btnReroll.style.opacity = '1';
                    btnTrigger.disabled = false; btnTrigger.querySelector('span').innerText = '新建H事件'; btnTrigger.style.opacity = '1';
                    btnSkip.disabled = true; btnSkip.style.opacity = '0.5';
                }

                // --- B. 威胁雷达 逻辑 ---
                const turnCount = getDeep(d, '系统状态.幕间回合计数', 0);
                const isFallen = getDeep(d, '主角.核心状态.人格状态') === '堕落';
                const threatPanel = document.getElementById('panel-threat-forecast');
                const panelTitleEl = document.getElementById('threat-panel-title');

                // 堕落线变为狩猎雷达
                if (isFallen) {
                    panelTitleEl.innerHTML = '<i class="fa-solid fa-crosshairs"></i> 狩猎雷达 (搜寻中)';
                    threatPanel.style.borderColor = 'rgba(247, 118, 142, 0.4)';
                    threatPanel.style.borderLeftColor = '#f7768e';
                    threatPanel.querySelector('.gm-label').style.color = '#f7768e';
                } else {
                    panelTitleEl.innerHTML = '<i class="fa-solid fa-radar"></i> 威胁雷达 (潜伏中)';
                    threatPanel.style.borderColor = 'rgba(224, 175, 104, 0.4)';
                    threatPanel.style.borderLeftColor = '#e0af68';
                    threatPanel.querySelector('.gm-label').style.color = '#e0af68';
                }

                setTxt('threat-turn-counter', `${turnCount}/5 ${turnCount >= 5 ? '(Ready!)' : ''}`);

                // 猎物类型锁定器 (仅堕落线)
                const preySelector = document.getElementById('fallen-prey-selector');
                const targetType = getDeep(d, '世界.当前关卡.战斗类型', '无');
                if (isFallen) {
                    preySelector.style.display = 'flex';
                    document.getElementById('btn-prey-random').style.borderColor = (targetType==='无'||targetType==='随机') ? 'var(--pleasure-color)' : 'var(--gm-border)';
                    document.getElementById('btn-prey-monster').style.borderColor = targetType==='魔物' ? 'var(--pleasure-color)' : 'var(--gm-border)';
                    document.getElementById('btn-prey-mg').style.borderColor = targetType==='魔法少女' ? 'var(--pleasure-color)' : 'var(--gm-border)';
                } else {
                    preySelector.style.display = 'none';
                }

                // 副主题选项卡
                const themeArea = document.getElementById('threat-theme-area');
                if (isFallen && targetType === '魔法少女') {
                    themeArea.style.display = 'none';
                } else {
                    themeArea.style.display = 'block';
                    const t_themesRaw = getDeep(d, '世界.当前关卡.核心主题', []);
                    const t_validThemes = Array.isArray(t_themesRaw) ? t_themesRaw.filter(t => t !== '$__META_EXTENSIBLE__$') : [];
                    const t_mainTheme = t_validThemes[0] || '未锁定';
                    const t_subTheme = t_validThemes[1] || null;

                    setTxt('threat-main-theme', t_mainTheme);
                    const subContainer = document.getElementById('threat-sub-options');
                    const subStatus = document.getElementById('threat-sub-status');

                    if (t_subTheme) { // 已经锁定副主题
                        subStatus.innerText = '[已锁定]';
                        subStatus.style.color = 'var(--combat-color)';
                        subContainer.innerHTML = `<div class="theme-tag" style="border-color:var(--combat-color); color:var(--combat-color); background:rgba(248, 113, 113, 0.1);">${t_subTheme} <span class="del" onclick="clearThreatSubTheme()">×</span></div>`;
                    } else { // 随机提供选项
                        subStatus.innerText = '[留空交由AI生成]';
                        subStatus.style.color = 'var(--hp-color)';
                        const pool = getDeep(d, '系统状态.Boss生成主题池', []).filter(t => t !== '$__META_EXTENSIBLE__$' && t !== t_mainTheme);
                        const shuffled = pool.sort(() => 0.5 - Math.random()).slice(0, 8); // 洗牌切出8个
                        subContainer.innerHTML = shuffled.map(t => `<div class="theme-tag" style="cursor:pointer;" onclick="lockThreatSubTheme('${t}')">${t}</div>`).join('');
                    }
                }
            }

            // 6. 其他独立模块渲染
            renderWorldNotes(d); 

        } catch (e) { console.error("[GM Render]", e); }
    };

    // --- 主题交互相关修改 ---
    window.injectTheme = async () => {
        const input = document.getElementById('new-theme-input');
        const val = input.value.trim();
        if(!val) return;

        // 读取下拉框判断要注入给谁
        const target = document.getElementById('theme-target-selector').value;
        const targetPath = target === 'hevent' ? 'stat_data.世界.幕间H事件.核心主题' : 'stat_data.世界.当前关卡.核心主题';

        let arr = getDeep(_currentMvuData, targetPath.replace('stat_data.', ''), []);
        if(!Array.isArray(arr)) arr = [];
        if(!arr.includes(val)) {
            const newArr = arr.filter(x => x !== '$__META_EXTENSIBLE__$');
            newArr.push(val); newArr.push('$__META_EXTENSIBLE__$');
            await gm_update(targetPath, newArr);
            input.value = ''; showToast("成功注入: " + val, "#theme-target-selector");
        }
    };

    window.removeTheme = async (rawPath, valToRemove) => {
        let arr = getDeep(_currentMvuData, rawPath, []);
        const newArr = arr.filter(t => t !== valToRemove);
        await gm_update('stat_data.' + rawPath, newArr);
    };
    window.rerollHEvent = async () => {
        const d = _currentMvuData;
        const allKinks = getDeep(d, '主角.快感状态.性癖', {});
        const validKinks = Object.keys(allKinks).filter(k => {
            const val = allKinks[k];
            return k !== '$meta' && k !== '$__META_EXTENSIBLE__$' && (val.等级 >= 1 || val.经验 >= 50);
        });
        let newThemes = [];
        if (validKinks.length > 0) {
            const primary = validKinks[Math.floor(Math.random() * validKinks.length)];
            newThemes.push(primary);
            const remaining = validKinks.filter(k => k !== primary);
            if (remaining.length > 0 && Math.random() > 0.3) newThemes.push(remaining[Math.floor(Math.random() * remaining.length)]);
        } else {
            const basicKinks = ['敏感体质', '羞耻心', '被动'];
            newThemes.push(basicKinks[Math.floor(Math.random() * basicKinks.length)]);
        }
        newThemes.push('$__META_EXTENSIBLE__$');
        await gm_update('stat_data.世界.幕间H事件.核心主题', newThemes);
        await gm_update('stat_data.世界.幕间H事件.名称', '无');
        await gm_update('stat_data.系统状态.幕间事件完成', false);
        showToast("Reroll Complete!", "#hevent-status-val");
    };

    window.triggerHEvent = async () => {
        const d = _currentMvuData;
        const heventName = getDeep(d, '世界.幕间H事件.名称', '无');
        const heventThemes = getDeep(d, '世界.幕间H事件.核心主题', []);
        const cleanThemes = heventThemes.filter(t => t && t !== '$__META_EXTENSIBLE__$');
        const isPreLocked = (!getDeep(d, '系统状态.幕间事件完成', true) && heventName === '无' && cleanThemes.length > 0);

        let targetName = 'EVENT：强制触发', targetThemes = cleanThemes;
        if (isPreLocked) {
            const proposedName = prompt(`预锁定主题: ${cleanThemes.join(' / ')}\\n请命名H事件:`, '突发遭遇');
            if (!proposedName) return;
            targetName = `EVENT：${proposedName}`;
        } else {
            const promptName = prompt('请输入H事件名称:', '意外事件');
            if (!promptName) return;
            targetName = `EVENT：${promptName}`;
            const promptTheme = prompt('输入核心主题 (逗号分隔):', '身体改造,强制露出');
            if (promptTheme) targetThemes = promptTheme.split(',').map(t => t.trim()).filter(Boolean);
            else targetThemes = ['意外遭遇'];
        }
        if (!targetThemes.includes('$__META_EXTENSIBLE__$')) targetThemes.push('$__META_EXTENSIBLE__$');
        await gm_update('stat_data.世界.幕间H事件.核心主题', targetThemes);
        await gm_update('stat_data.世界.幕间H事件.名称', targetName);
        await gm_update('stat_data.系统状态.幕间事件完成', false);
        showToast("Started!", "#hevent-status-val");
    };

    window.skipHEvent = async () => {
        if (confirm("确定要强制结算并跳过当前幕间事件吗？")) {
            await gm_update('stat_data.世界.幕间H事件.名称', '无');
            await gm_update('stat_data.世界.幕间H事件.核心主题', ['$__META_EXTENSIBLE__$']);
            await gm_update('stat_data.系统状态.幕间事件完成', true);
            showToast("Skipped.", "#hevent-status-val");
        }
    };

    window.rerollThreatMainTheme = async () => {
        const pool = getDeep(_currentMvuData, '系统状态.Boss生成主题池', []).filter(t => t !== '$__META_EXTENSIBLE__$');
        if (pool.length > 0) {
            const newMain = pool[Math.floor(Math.random() * pool.length)];
            // 重随主主题时，会顺便清空已选的副主题，保持纯净
            await gm_update('stat_data.世界.当前关卡.核心主题', [newMain, '$__META_EXTENSIBLE__$']);
            showToast("主主题已重随", "#threat-turn-counter");
        }
    };

    window.lockThreatSubTheme = async (theme) => {
        const themes = getDeep(_currentMvuData, '世界.当前关卡.核心主题', []).filter(t => t !== '$__META_EXTENSIBLE__$');
        if (themes.length > 0) {
            await gm_update('stat_data.世界.当前关卡.核心主题', [themes[0], theme, '$__META_EXTENSIBLE__$']);
            showToast("副主题已锁定", "#threat-turn-counter");
        }
    };

window.lockPreyType = async (type) => {
        await gm_update('stat_data.世界.当前关卡.战斗类型', type);
        showToast(`已锁定: ${type==='无'?'随机猎物':type}`, "#threat-turn-counter");
    };

    window.clearThreatSubTheme = async () => {
        const themes = getDeep(_currentMvuData, '世界.当前关卡.核心主题', []).filter(t => t !== '$__META_EXTENSIBLE__$');
        if (themes.length > 0) {
            await gm_update('stat_data.世界.当前关卡.核心主题', [themes[0], '$__META_EXTENSIBLE__$']);
            showToast("副主题已清除", "#threat-turn-counter");
        }
    };

    window.forceThreatEncounter = async () => {
        await gm_update('stat_data.系统状态.幕间回合计数', 5);
        showToast("已强制推进至可遭遇状态", "#threat-turn-counter");
    };

    window.restoreSnapshot = async () => {
        if(!_gmSnapshot) { alert("无快照可恢复"); return; }
        if(confirm("确定撤销本次打开面板后的所有修改？")) {
            await gm_update('stat_data', _gmSnapshot);
            showToast("Reverted!", "#save-status");
        }
    };

    window.renderWorldNotes = (data) => {
        const notes = getDeep(data, '世界.世界观备注', {});
        const container = document.getElementById('world-notes-list');
        if (!container) return;

        const validEntries = Object.entries(notes).filter(([k]) => k !== '$meta' && k !== '$__META_EXTENSIBLE__$');

        if (validEntries.length === 0) {
            container.innerHTML = '<div style="text-align:center; opacity:0.5; padding:10px;">暂无特殊设定</div>';
            return;
        }

        container.innerHTML = validEntries.map(([k, v]) => `
            <div class="note-item">
                <span class="note-key">${k}</span>
                <div class="note-val">${v}</div>
                <div class="note-actions">
                    <button class="note-btn edit" onclick="editNote('${k}')" title="编辑"><i class="fa-solid fa-pen"></i></button>
                    <button class="note-btn del" onclick="deleteWorldNote('${k}')" title="删除"><i class="fa-solid fa-trash"></i></button>
                </div>
            </div>
        `).join('');
    };

    window.toggleNoteEditor = () => {
        const el = document.getElementById('world-note-editor');
        if (el.style.display === 'none') {
            el.style.display = 'block';
            document.getElementById('new-note-key').value = '';
            document.getElementById('new-note-val').value = '';
        } else {
            el.style.display = 'none';
        }
    };

    window.editNote = (key) => {
        const d = _currentMvuData; 
        const val = getDeep(d, `世界.世界观备注.${key}`, '');
        document.getElementById('world-note-editor').style.display = 'block';
        document.getElementById('new-note-key').value = key;
        document.getElementById('new-note-val').value = val;
    };

    window.saveWorldNote = async () => {
        const key = document.getElementById('new-note-key').value.trim();
        const val = document.getElementById('new-note-val').value.trim();
        if (!key) { alert("Key不能为空"); return; }
        await gm_update(`stat_data.世界.世界观备注.${key}`, val);
        showToast(`Note Saved: ${key}`, "#save-status");
        document.getElementById('world-note-editor').style.display = 'none';
    };

    window.deleteWorldNote = async (key) => {
        if (confirm(`确定要删除关于 [${key}] 的设定吗？`)) {
            await gm_update(`stat_data.世界.世界观备注.${key}`, null, 'remove');
            showToast(`Note Deleted`, "#save-status");
        }
    };
</script>
