                    </div>
                    <div id="event-list-container" class="event-list"></div>
                    <button class="gm-btn gray full-width" style="margin-top:5px; font-size:0.8em; padding:4px;" onclick="gm_update('stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {})">Xóa tất cả sự kiện đang chờ</button>
