                        <div class="quick-actions">
                            <button class="mini-btn" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', -10, 'add')">-10</button>
                            <button class="mini-btn blue" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', 999)">Đầy</button>
