                    </div>
                    <div class="control-row">
                        <span class="label" style="color:#f7768e">Khoái cảm</span>
                        <input type="number" id="inp-pleasure" class="gm-input num" style="color:#f7768e; border-color:#f7768e;" onchange="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', Number(this.value))">
                        <div class="quick-actions">
                            <button class="mini-btn" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', -50, 'add')">-50</button>
                            <button class="mini-btn pink" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', 9999)">Suy sụp</button>
                        </div>
                    </div>
                    <div class="control-row">
                        <span class="label" style="color:#bb9af7">Ô nhiễm</span>
                        <input type="number" id="inp-corruption" class="gm-input num" style="color:#bb9af7; border-color:#bb9af7;" onchange="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', Number(this.value))">
                        <div class="quick-actions">
                            <button class="mini-btn" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', -10, 'add')">-10</button>
                            <button class="mini-btn purple" onclick="gm_update('stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', 0)">Thanh tẩy</button>
                        </div>
                    </div>
                </div>
                <div class="gm-section">
                    <div class="gm-label"><i class="fa-solid fa-wand-magic-sparkles"></i> Sửa chữa nhanh</div>
                    <div class="gm-btn-group">
                        <button class="gm-btn blue" onclick="(async()=>{ 
                            const parts = ['Khuôn_mặt','Ngực','Cánh_tay','Eo_bụng','Mông','Vùng_kín','Chân'];
                            for(let p of parts) await gm_update(`stat_data.Nhân_vật_chính.Tình_trạng_các_bộ_phận_cơ_thể.${p}.Trạng_thái_quần_áo`, 'Nguyên_vẹn');
                            for(let p of parts) await gm_update(`stat_data.Nhân_vật_chính.Tình_trạng_các_bộ_phận_cơ_thể.${p}.Tình_trạng_hiện_tại`, 'Không');
                        })()"><i class="fa-solid fa-shirt"></i> Khôi phục y phục</button>
                        <button class="gm-btn green" onclick="(async()=>{ 
                            await gm_update('stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
                            await gm_update('stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Nguồn_gốc', {});
                            await gm_update('stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Dị_vật_bên_trong', {});
                            await gm_update('stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Dị_vật_trong_tử_cung.Danh_sách_dị_vật', {});
                            await gm_update('stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Trạng_thái_thụ_thai', 'Chưa_thụ_thai');
                        })()"><i class="fa-solid fa-shower"></i> Thanh tẩy cơ thể</button>
                    </div>
                </div>
            </div>

            <div id="gm-tab-world" class="gm-content">
                <div class="gm-section">
                    <div class="gm-label"><i class="fa-solid fa-users"></i> Kiểm soát danh tiếng</div>
                    <div class="control-row">
                        <span class="label">Độ nổi tiếng</span>
                        <input type="range" class="gm-range" min="0" max="100" step="5" id="range-fame" oninput="document.getElementById('inp-fame').value=this.value" onchange="gm_update('stat_data.Danh_tiếng.Độ_nổi_tiếng', Number(this.value))">
                        <input type="number" id="inp-fame" class="gm-input num mini" onchange="gm_update('stat_data.Danh_tiếng.Độ_nổi_tiếng', Number(this.value))">
                    </div>
                    <div class="control-row">
                        <span class="label">Đánh giá</span>
                        <input type="range" class="gm-range" min="-100" max="100" step="5" id="range-rep" oninput="document.getElementById('inp-rep').value=this.value" onchange="gm_update('stat_data.Danh_tiếng.Đánh_giá', Number(this.value))">
                        <input type="number" id="inp-rep" class="gm-input num mini" onchange="gm_update('stat_data.Danh_tiếng.Đánh_giá', Number(this.value))">
                    </div>
                </div>

                <div class="gm-section">
                    <div class="gm-label">
                        <span><i class="fa-solid fa-book-journal-whills"></i> Ghi chú thế giới quan / Thiết lập</span>
                        <button class="mini-btn blue" onclick="toggleNoteEditor()" title="Thêm thiết lập mới">+</button>
                    </div>

                    <div id="world-notes-list" class="notes-list"></div>

                    <div id="world-note-editor" style="display:none; margin-top:8px; background:rgba(0,0,0,0.2); padding:8px; border-radius:6px; border:1px solid var(--gm-border);">
                        <div style="margin-bottom:4px; font-size:0.8em; opacity:0.7;">Chủ đề (Khóa):</div>
                        <input type="text" id="new-note-key" class="gm-input" placeholder="Ví dụ: Điểm yếu kẻ thù / Quan hệ_Sayaka">
                        <div style="margin:4px 0; font-size:0.8em; opacity:0.7;">Nội dung (Giá trị):</div>
                        <textarea id="new-note-val" class="gm-input" rows="3" placeholder="Nhập chi tiết thiết lập..."></textarea>
                        <div class="gm-btn-group" style="margin-top:8px;">
                            <button class="gm-btn green" onclick="saveWorldNote()"><i class="fa-solid fa-save"></i> Lưu / Cập nhật</button>
                            <button class="gm-btn gray" onclick="toggleNoteEditor()">Hủy</button>
