                <div class="gm-section">
                    <div class="gm-label"><i class="fa-solid fa-toolbox"></i> Công cụ khác</div>
                    <div class="gm-btn-group">
                        <button class="gm-btn" onclick="gm_update('stat_data.Nhân_vật_chính.Túi_đồ', {})"><i class="fa-solid fa-box-open"></i> Xóa túi đồ</button>
                        <button class="gm-btn" onclick="gm_update('stat_data.Ghi_chép.Tổng_số_lần_thất_bại', 0)"><i class="fa-solid fa-eraser"></i> Reset thất bại</button>
                    </div>
                </div>
            </div>
        </div>
    </div>

<script>
    let lastActiveTabId = 'panel-character';
    let _gmSnapshot = null;
    let _currentMvuData = null;

    // Hàm cập nhật DOM được tối giản hóa
    function updateDOM(fromNode, toNode) { if (!fromNode || !toNode) return; const fromAttrs = fromNode.attributes, toAttrs = toNode.attributes; for (const attr of toAttrs) { if (fromNode.getAttribute(attr.name) !== attr.value) fromNode.setAttribute(attr.name, attr.value); } for (const attr of fromAttrs) { if (!toNode.hasAttribute(attr.name)) fromNode.removeAttribute(attr.name); } const fromChildren = Array.from(fromNode.childNodes), toChildren = Array.from(toNode.childNodes); for (let i = 0; i < Math.max(fromChildren.length, toChildren.length); i++) { const fromChild = fromChildren[i], toChild = toChildren[i]; if (!toChild) { fromNode.removeChild(fromChild); } else if (!fromChild) { fromNode.appendChild(toChild.cloneNode(true)); } else if (fromChild.nodeType !== toChild.nodeType || fromChild.tagName !== toChild.tagName) { fromNode.replaceChild(toChild.cloneNode(true), fromChild); } else if (fromChild.nodeType === Node.TEXT_NODE) { if (fromChild.textContent !== toChild.textContent) { fromChild.textContent = toChild.textContent; } } else if (fromChild.nodeType === Node.ELEMENT_NODE) { updateDOM(fromChild, toChild); } } }

    const getValue = (data, path, defaultValue = null) => { const value = path.split('.').reduce((acc, part) => acc && acc[part], data); return (value === undefined || value === null) ? defaultValue : value; };
    const getDeep = (obj, path, def) => path.split('.').reduce((acc, part) => acc && acc[part], obj) ?? def;

    const createDetailItem = (label, value, iconClass = null) => { if (!value || value === 'Chờ_thiết_lập' || value === 'Không') return ''; const iconHtml = iconClass ? `<i class="fa-solid ${iconClass}"></i>` : ''; return `<div class='item-label'>${iconHtml}${label}</div><div class='item-value'>${value}</div>`; };
    const createRichItem = (label, mainText, subHtml, iconClass = null) => {
        if (!mainText || mainText === 'Chờ_thiết_lập' || mainText === 'Không') return '';
        const iconHtml = iconClass ? `<i class="fa-solid ${iconClass}"></i>` : '';
        const subContent = subHtml ? `<div class='rich-sub-text'>${subHtml}</div>` : '';
        return `
        <div class='item-label'>${iconHtml}${label}</div>
        <div class='rich-value-box'>
            <div class='rich-main-text'>${mainText}</div>
            ${subContent}
        </div>`;
    };

    const TOOLTIP_DEFINITIONS = {
        'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Điểm sinh mệnh của nhân vật, đại diện cho khả năng chịu đựng sát thương trong chiến đấu.</div><div class='label'>Cơ chế:</div><div class='value'>Giảm do các đòn tấn công của kẻ thù, có thể phục hồi qua nghỉ ngơi hoặc kỹ năng cụ thể.</div><div class='label'>Về 0:</div><div class='value'>Nhân vật sẽ rơi vào trạng thái "Kiệt sức chờ nhục nhã" và thua trận, thụ động chịu sự xâm phạm không ngừng của kẻ thù.</div>`,
        'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại': {
            'Lương_thiện': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Năng lượng cốt lõi để sử dụng kỹ năng ma pháp.</div><div class='label'>Sử dụng:</div><div class='value'>Tất cả kỹ năng chủ động (Tấn công, phòng thủ, hỗ trợ) đều tiêu hao ma lực.</div><div class='label'>Về 0:</div><div class='value'>Không thể sử dụng năng lực cốt lõi và có thể bị ép buộc giải trừ biến hình, rơi vào nguy cơ.</div>`,
            'Sa_ngã': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Nguồn gốc để điều khiển sức mạnh sa ngã.</div><div class='label'>Cơ chế:</div><div class='value'>Bất kể trêu đùa con mồi hay thể hiện sức mạnh đều cần tiêu hao dục lực.</div><div class='label'>Chức năng:</div><div class='value'>Đó là kết tinh khoái lạc của bạn, cũng là nhiên liệu sử dụng ma lực.</div>`
        },
        'Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Mức độ khoái cảm sinh lý tích lũy khi bị tấn công cụ thể hoặc kích thích giác quan.</div><div class='label'>Cơ chế:</div><div class='value'>Khi giá trị này đạt hoặc vượt qua 【Ngưỡng cao trào】 hiện tại, sự kiện cao trào sẽ được kích hoạt.</div><div class='label'>Hậu quả chính:</div><div class='value'>Cao trào sẽ làm giảm thể lực, tăng độ ô nhiễm, đồng thời tăng đáng kể kinh nghiệm sở thích tình dục tương ứng và thiết lập lại điểm khoái cảm.</div>`,
        'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm': {
            'Lương_thiện': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Mức độ tinh thần và linh hồn bị sức mạnh tà ác ô nhiễm.</div><div class='label'>Nguồn gốc:</div><div class='value'>Gánh chịu các đòn tấn công tinh thần tẩy não, bị xuất tinh bên trong hoặc nhận được khi cao trào.</div><div class='label'>Hậu quả:</div><div class='value'>Sự gia tăng ô nhiễm sẽ ảnh hưởng đến thể xác và tinh thần nhân vật chính. Khi đạt 100%, sự kiện chọn lựa sa ngã quyết định vận mệnh sẽ được kích hoạt.</div>`,
            'Sa_ngã': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Sự sủng ái nhận được từ chủ nhân, hoặc sự thể hiện bản chất sa ngã của chính mình.</div><div class='label'>Ý nghĩa:</div><div class='value'>Đại diện cho sự phục tùng và mức độ bạn kiểm soát dục vọng. Giá trị này càng cao, sức mạnh và sự tồn tại của bạn càng vững chắc.</div>`
        },
        'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Năng lượng phản công tích tụ được khi chiến đấu với kẻ thù và chịu đựng trong nghịch cảnh.</div><div class='label'>Thu thập:</div><div class='value'>Tích lũy qua đòn tấn công hiệu quả, hoặc khi chịu đòn tấn công và xâm phạm của kẻ thù.</div><div class='label'>Công dụng:</div><div class='value'>Khi nạp đến 100%, có thể tuyên bố tung đòn kết liễu tất sát, hoặc có thể dùng để thanh tẩy trạng thái mang thai trong cơ thể.</div>`,
        'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế': `<div class='label'>Tác dụng cốt lõi:</div><div class='value'>Năng lượng hắc ám hội tụ lại trong quá trình tận hưởng chiến đấu và khoái lạc.</div><div class='label'>Thu thập:</div><div class='value'>Tích lũy qua việc trêu đùa đối thủ và tận hưởng khoái cảm trong chiến đấu.</div><div class='label'>Công dụng:</div><div class='value'>Khi nạp đến 100%, có thể tuyên bố sử dụng đòn tất sát mang tên "Lãnh Vực Phúc Âm", đặt dấu chấm hết cho trận đấu.</div>`
    };

    const renderProgressItem = (item, data, isFallen) => {
        const value = getValue(data, item.path, 0);
        const max = item.options.max || 100;
        const percentage = Math.max(0, Math.min(100, (value / max) * 100));
        const orgasmIndicator = (item.path.includes('Chỉ_số_khoái_cảm') && value >= max) ? `<span title='Cao trào!'>⚡</span>` : '';

        let tooltipText = TOOLTIP_DEFINITIONS[item.path] || null;
        if (typeof tooltipText === 'object' && tooltipText !== null) {
            tooltipText = isFallen ? tooltipText['Sa_ngã'] : tooltipText['Lương_thiện'];
        }
        const tooltipIconHtml = tooltipText 
            ? `<span class='has-tooltip'><i class="fa-solid fa-circle-info info-icon-pc tooltip-trigger"></i><span class='custom-tooltip'>${tooltipText}</span></span>`
            : '';

        return `<div class='progress-item'><div class='progress-label'><span><i class='${item.options.icon}'></i> <span>${item.label}</span> ${tooltipIconHtml} ${orgasmIndicator}</span><span class='progress-value'>${Math.round(value)}/${max}</span></div><div class='progress-bar'><div class='progress-fill' style='width: ${percentage}%; background: ${item.options.color};'></div></div></div>`;
    };

const renderCharacterInfo = (data, personality) => {
        let masterInfoHtml = '';
        if (personality === 'Sa_ngã') {
            const masterName = getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chủ_nhân', 'Không');
            if (masterName && masterName !== 'Không') {
                masterInfoHtml = `
                <div class='master-banner'>
                    <div class='master-banner-label'><i class="fa-solid fa-crown"></i> <span>Chủ nhân❤</span></div>
                    <div class='master-banner-value'>${masterName}</div>
                </div>`;
            }
        }

        const fame = getValue(data, 'Danh_tiếng.Độ_nổi_tiếng', 0);
        const reputationScore = getValue(data, 'Danh_tiếng.Đánh_giá', 0);
        let fameLevel, reputationLevel, reputationHtml = '';

        if (fame < 15) { fameLevel = "Vô danh"; }
        else if (fame < 45) { fameLevel = "Truyền thuyết đô thị"; }
        else if (fame < 85) { fameLevel = "Đề tài bàn tán"; }
        else { fameLevel = "Ai ai cũng biết"; }

        if (fame >= 15) {
            if (personality === 'Lương_thiện') {
                if (reputationScore >= 70) { reputationLevel = "Anh hùng thánh thiện"; }
                else if (reputationScore >= 30) { reputationLevel = "Người bảo vệ đáng tin cậy"; }
                else if (reputationScore > -30) { reputationLevel = "Ma pháp thiếu nữ gây tranh cãi"; }
                else if (reputationScore > -70) { reputationLevel = "Kẻ dâm đãng vô năng"; }
                else { reputationLevel = "Bồn chứa tinh công cộng"; }
            } else { 
                if (reputationScore <= -70) { reputationLevel = "Tai ương đáng sợ"; }
                else if (reputationScore <= -30) { reputationLevel = "Ma pháp thiếu nữ sa ngã đáng gờm"; }
                else if (reputationScore < 30) { reputationLevel = "Chẳng đáng sợ chút nào lại còn dâm đãng"; }
                else { reputationLevel = "Thần tượng khiêu dâm quốc dân"; }
            }
            const isDGrade = (personality === 'Lương_thiện' && reputationScore <= -70) || (personality === 'Sa_ngã' && reputationScore >= 30);
            const badgeStyle = isDGrade ? 'border-color:var(--pleasure-color); color:var(--pleasure-color); box-shadow:none; background:rgba(247,118,142,0.1);' : '';
            reputationHtml = createRichItem('Đánh giá', reputationScore, `<span class='rank-badge' style='${badgeStyle}'>${reputationLevel}</span>`, 'fa-gavel');
        }

        const famType = getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Loại_sử_ma_đồng_hành');
        let familiarHtml = '';
        if (famType && famType !== 'Chờ_thiết_lập') {
            const famPers = getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Tính_cách_sử_ma_đồng_hành', 'Chưa_rõ');
            const famRel = getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Quan_hệ_sử_ma_và_nhân_vật_chính', 'Đồng_hành');
            familiarHtml = createRichItem('Sử ma', famType, 
                `<span class='info-tag' title='Tính cách'><i class="fa-regular fa-face-smile"></i>${famPers}</span>
                 <span class='info-tag' title='Quan hệ'><i class="fa-solid fa-link"></i>${famRel}</span>`, 
            'fa-paw');
        }

        return `
            ${masterInfoHtml}
            <div class=\"details-grid\">
                <div class='details-section-header'><i class=\"fa-solid fa-address-card\"></i> <b>Thiết lập cốt lõi</b></div>
                ${createDetailItem('Tuổi', getValue(data, 'Nhân_vật_chính.Thông_tin_cơ_bản.Tuổi'), 'fa-cake-candles')}
                ${createRichItem('Thân phận', getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Thân_phận_&_Nghề_nghiệp') || getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Thân_phận/Nghề_nghiệp'), '', 'fa-user-tie')}
                ${createRichItem('Tính cách', getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Đặc_điểm_tính_cách'), '', 'fa-masks-theater')}

                <div class='details-section-header'><i class=\"fa-solid fa-wand-sparkles\"></i> <b>Khế ước ma pháp</b></div>
${createDetailItem('Sức mạnh', getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_cơ_bản', 50), 'fa-burst')}
                ${createDetailItem('Vũ trang', getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Vũ_trang'), 'fa-gavel')}
                ${createDetailItem('Năng lực cốt lõi', getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Năng_lực_cốt_lõi'), 'fa-bolt')}

${(() => {
    const rawColor = getValue(data, 'Nhân_vật_chính.Thông_tin_cá_nhân.Màu_đại_diện', 'Chờ_thiết_lập');
    const cleanText = String(rawColor).replace(/\s*\([^)]*#[0-9a-fA-F]{6}[^)]*\)/g, '').trim();
    const hexCodes = String(rawColor).match(/#[0-9a-fA-F]{6}/g);
    let bgStyle = 'var(--accent-color)'; 
    if (hexCodes && hexCodes.length > 0) {
        if (hexCodes.length === 1) { bgStyle = hexCodes[0]; } else { bgStyle = `linear-gradient(90deg, ${hexCodes.join(', ')})`; }
    } 
    else if (['Vàng', 'gold'].some(s => String(rawColor).includes(s))) { bgStyle = '#FFD700'; }
    else if (['Đỏ', 'red'].some(s => String(rawColor).includes(s))) { bgStyle = '#FF6B6B'; }
    else if (['Xanh', 'blue'].some(s => String(rawColor).includes(s))) { bgStyle = '#4D96FF'; }
    else if (['Hồng', 'pink'].some(s => String(rawColor).includes(s))) { bgStyle = '#FFB6C1'; }
    else if (['Tím', 'purple'].some(s => String(rawColor).includes(s))) { bgStyle = '#BB9AF7'; }
    else if (['Đen', 'black'].some(s => String(rawColor).includes(s))) { bgStyle = '#333333'; }

    return createRichItem('Màu đại diện', cleanText, 
