            let tooltipContent = `<div class='label'>Bộ phận:</div><div class='value'>${partText}</div><div class='label'>Chi tiết:</div><div class='value'>${detailsText}</div><div class='label'>Nguồn gốc:</div><div class='value'>${sourceText}</div>`;
