        if (!modificationsHtml.trim()) modificationsHtml = '<span style="opacity:0.5">Cơ thể trong sáng không tì vết.</span>';

        const vagState = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Trạng_thái_hiện_tại', 'Thư_giãn');
        const vagWetness = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Độ_ẩm_ướt', 'Ít');
        const vagDetails = `${vagState} <span style="opacity:0.7; font-size:0.9em">(${vagWetness})</span>`;

        const pregState = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Trạng_thái_thụ_thai', 'Chưa_thụ_thai');
        let pregDisplay = pregState;
        if (pregState !== 'Chưa_thụ_thai' && pregState !== 'Không') {
            const pregSource = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Thông_tin_mang_thai.Nguồn_gốc_mang_thai', 'Chưa_rõ');
            if (pregSource && pregSource !== 'Không') {
                pregDisplay += ` <span style="font-size:0.85em; opacity:0.8; color:var(--ultimate-color);">(${pregSource})</span>`;
            }
        }

let semenHtml = '';
        const semenAmount = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
        // 【Sửa lỗi】 Giá trị mặc định thay đổi từ 200 thành 50, khớp với logic mở rộng của BE
        const vagCapacity = getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Dung_tích_tối_đa', 50); 
        const semenSources = Object.keys(getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Nguồn_gốc', {})).filter(s => s !== '$meta' && s !== '$__META_EXTENSIBLE__$');

        if (true) {
            const pct = Math.min(100, (semenAmount / vagCapacity) * 100);
            const isOverflow = semenAmount >= vagCapacity;
            let riskTag = '', riskLevel = 'Yên bình';
            if (isOverflow) { riskLevel = 'Tràn ngập giới hạn'; riskTag = 'risk-high'; }
            else if (pct > 80) { riskLevel = 'Bụng dưới phình to'; riskTag = 'risk-high'; }
            else if (pct > 50) { riskLevel = 'Bán đầy'; }
            else if (pct > 20) { riskLevel = 'Tích tụ'; }

            // 【Thêm mới】 Logic phân cấp hình thái bình chứa
            let tierClass = 'flask-tier-1';
