            let capColor = 'inherit';
            if (vagCapacity >= 200) { tierClass = 'flask-tier-4'; capLabel = '❤Vườn ươm hóa'; capColor = 'var(--pleasure-color)'; }
            else if (vagCapacity >= 150) { tierClass = 'flask-tier-3'; capLabel = 'Khai phá sâu'; capColor = '#f472b6'; }
            else if (vagCapacity >= 100) { tierClass = 'flask-tier-2'; capLabel = 'Đã mở rộng'; capColor = '#fb7185'; }

            let sourceTagsHtml = semenSources.length > 0 
                ? semenSources.slice(0, 3).map(s => `<span class='bio-tag'>${s.split(':')[0]}</span>`).join('') 
                : `<span class='bio-tag' style="opacity:0.5">Sạch sẽ</span>`;
            if (semenSources.length > 3) sourceTagsHtml += `<span class='bio-tag'>+${semenSources.length - 3}</span>`;

            // Kết hợp class hình thái và cảnh báo tràn
            const flaskClass = `bio-flask ${tierClass} ${isOverflow ? 'danger' : ''}`;

            semenHtml = `
            <div class="bio-container-widget">
                <div class="${flaskClass}">
                    <div class="liquid-wave" style="height: ${pct}%"></div>
                </div>
                <div class="bio-data" style="width: 100%;">
                    <div class="bio-header" style="display:flex; justify-content:space-between; align-items:baseline; margin-bottom:4px;">
                        <div class="bio-title" style="font-weight:bold; color:var(--accent-color);">
                            <i class="fa-solid fa-flask"></i> Dung tích bên trong 
                            <span style="font-size:0.75em; color:${capColor}; margin-left:4px; font-weight:normal;">[${capLabel}]</span>
                        </div>
                        <div class="bio-tag ${riskTag}" style="font-size:0.7em;">${riskLevel}</div>
                    </div>
                    <div class="bio-readout" style="font-family:var(--font-header); font-size:1.15em; margin-bottom:4px; font-weight:600;">
                        ${semenAmount} <small style="opacity:0.6; font-size:0.75em; font-weight:normal;">/ ${vagCapacity} ml</small>
                    </div>
                    <div class="bio-tags">${sourceTagsHtml}</div>
                </div>
            </div>`;
        }

        const itemObj = getValue(data, 'Nhân_vật_chính.Túi_đồ', {});
        const itemKeys = Object.keys(itemObj).filter(k => k !== '$meta' && k !== '$__META_EXTENSIBLE__$');
        let itemsHtml = '';
        if (itemKeys.length > 0) {
            const tagsHtml = itemKeys.map(k => {
