                if (val && val !== 1 && val !== '1' && val !== true && val !== 'Có') {
                    content += ` <span style="opacity:0.6; padding-left:5px; margin-left:3px; border-left:1px solid rgba(255,255,255,0.2); font-size:0.9em;">${val}</span>`;
                }
                return `<span class="bio-tag" style="background:rgba(122, 162, 247, 0.1); border-color:rgba(122, 162, 247, 0.2); color:var(--text-color);">${content}</span>`;
            }).join('');
            itemsHtml = `<div class='details-section-header'><i class="fa-solid fa-box-open"></i> <b>Vật phẩm sở hữu</b></div><div class="bio-tags" style="margin-bottom:8px; grid-column: 1 / -1;">${tagsHtml}</div>`;
        } else {
            itemsHtml = `<div class='details-section-header'><i class="fa-solid fa-box-open"></i> <b>Vật phẩm sở hữu</b></div><div style="opacity:0.4; font-size:0.9em; padding-left:4px; grid-column: 1 / -1;">(Trống)</div>`;
        }

        const formatObjs = (dataObj) => {
            if (!dataObj || typeof dataObj !== 'object') return '<span style="opacity:0.5">Không có</span>';
            const validKeys = Object.keys(dataObj).filter(k => k !== '$meta' && k !== '$__META_EXTENSIBLE__$');
            if (validKeys.length === 0) return '<span style="opacity:0.5">Không có</span>';
            return validKeys.map(k => {
                const v = dataObj[k];
                const desc = (typeof v === 'object') ? (v.Đặc_điểm || v.Trạng_thái || v.description || 'Tồn tại') : v;
