            ${createDetailItem('Bên trong tử cung', formatObjs(getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Dị_vật_trong_tử_cung.Danh_sách_dị_vật')), 'fa-cubes')}
