    const renderRecords = (data, personality) => {
        const KINK_LEVELS = { 
            0: { name: 'Chưa thức tỉnh', xp_needed: 100, icon: 'fa-circle-notch' }, 
            1: { name: 'Mới chớm', xp_needed: 250, icon: 'fa-leaf' }, 
            2: { name: 'Thành thạo', xp_needed: 500, icon: 'fa-layer-group' }, 
            3: { name: 'Say đắm', xp_needed: 1000, icon: 'fa-heart' }, 
            4: { name: 'Đỉnh điểm', xp_needed: Infinity, icon: 'fa-crown' } 
        };

        const kinks = getValue(data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Sở_thích_tình_dục', {});
        const kinkEntries = Object.entries(kinks)
            .filter(([key, val]) => key !== '$meta' && (val.Kinh_nghiệm > 0 || val.Kinh_nghiệm > 0))
            .sort(([, a], [, b]) => (b.Kinh_nghiệm || 0) - (a.Kinh_nghiệm || 0));

        let kinkHtml = '';
        if (kinkEntries.length === 0) {
            kinkHtml = `<div style='grid-column: 1/-1; text-align:center; color:var(--text-secondary); padding:10px;'>Chưa thức tỉnh sở thích tình dục</div>`;
        } else {
            kinkHtml = kinkEntries.map(([key, val]) => {
                const exp = val.Kinh_nghiệm || 0;
                const level = val.Cấp_độ || 0;
                const levelInfo = KINK_LEVELS[level] || KINK_LEVELS[0];
                const isMax = levelInfo.xp_needed === Infinity;
                const rankClass = `rank-${Math.min(level, 4)}`;
                const prevXp = level > 0 ? KINK_LEVELS[level - 1].xp_needed : 0;

                let progressPercent = 0;
                if (isMax) { progressPercent = 100; } 
                else { progressPercent = Math.max(0, Math.min(100, ((exp - prevXp) / (levelInfo.xp_needed - prevXp)) * 100)); }

                let xpDisplayHtml = isMax 
                    ? `<span class="kink-xp is-max">${exp} <small>MAX</small></span>`
                    : `<span class="kink-xp">${exp} <small>/ ${levelInfo.xp_needed}</small></span>`;
                const barColor = isMax ? 'var(--ultimate-color)' : 'var(--accent-color)';

                return `
                <div style="grid-column: 1/-1; margin-bottom:6px;">
                    <div class="kink-row">
                        <div class="kink-name ${rankClass}">
                            <i class="fa-solid ${levelInfo.icon} rank-icon"></i>
                            <span>${key} <span style="font-size:0.8em; opacity:0.8; font-weight:normal;">Lv.${level}</span></span>
                        </div>
                        <div>${xpDisplayHtml}</div>
                    </div>
                    <div class="kink-progress-container">
                        <div class="progress-fill" style="width: ${progressPercent}%; background: ${barColor}; box-shadow: 0 0 10px ${barColor};"></div>
                    </div>
                </div>`;
            }).join('');
        }

        const getListValues = (path) => {
            const raw = getValue(data, path, {});
            if (Array.isArray(raw)) return raw;
            if (typeof raw === 'object' && raw !== null) return Object.values(raw);
            return [];
        };

        const bossesList = getListValues('Ghi_chép.Boss_đã_đánh_bại');
        let bossesHtml = bossesList.filter(b => b !== '$__META_EXTENSIBLE__$').map(boss => { 
            const bossName = (typeof boss === 'object' ? boss.Tên : boss) || 'Chưa_rõ'; 
            const tagsArray = (typeof boss === 'object' ? boss.Chủ_đề_cốt_lõi : []) || []; 
            const result = (typeof boss === 'object' ? boss.Kết_quả : 'WIN') || 'WIN';
            const tagsText = (tagsArray.length > 0) ? `<div class='label'>Chủ đề cốt lõi:</div><div class='value'>${tagsArray.join(', ')}</div>` : 'Không có chủ đề đặc thù'; 

            let icon, styleClass;
            if (result === 'LOSE') {
                icon = 'fa-heart-crack'; styleClass = 'color: var(--combat-color); opacity: 0.8;';
            } else {
                icon = 'fa-skull-crossbones'; styleClass = 'color: var(--text-color);';
            }
            return `<span class='has-tooltip' style='display:inline-block; margin-right:8px; ${styleClass}'><span class=\"tooltip-trigger\"><i class=\"fa-solid ${icon}\"></i> ${bossName}</span><span class='custom-tooltip'>${tagsText}<br><span style='font-size:0.8em; opacity:0.6'>${result === 'LOSE' ? 'Kỷ lục bại trận' : 'Thảo phạt thành công'}</span></span></span>`; 
        }).join(' <br>');

        const childrenList = getListValues('Ghi_chép.Hậu_duệ_đã_sinh');
        const validChildren = childrenList.filter(c => typeof c === 'object' && c !== null);
        const childrenDisplayHtml = (validChildren.length > 0) ? validChildren.map(child => {
            const childName = child.Tên || 'Trẻ sơ sinh'; 
            const childSource = child.Nguồn_gốc || 'Chưa_rõ'; 
            const childFeatures = child.Đặc_điểm || 'Không'; 
            const tooltipContent = `<div class='label'>Nguồn gốc:</div><div class='value'>${childSource}</div><div class='label'>Đặc điểm:</div><div class='value'>${childFeatures}</div>`; 
            return `<span class='has-tooltip'><span class=\"tooltip-trigger\">👼 ${childName}</span><span class='custom-tooltip'>${tooltipContent}</span></span>`; 
        }).join(' <br>') : '';

        const recordsHeader = (personality === 'Lương_thiện') ? 'Kỷ lục thảo phạt' : 'Chiến lợi phẩm';
        const recordsIcon = (personality === 'Lương_thiện') ? 'fa-skull-crossbones' : 'fa-gem';
        const childrenLabel = (personality === 'Lương_thiện') ? 'Sinh hạ hậu duệ' : 'Tác phẩm của tôi';

        return `<div class=\"details-grid\">
            <div class='details-section-header'><i class=\"fa-solid fa-arrow-trend-up\"></i> <b>Khai phá sở thích</b></div>
            ${kinkHtml}
            <div class='details-section-header'><i class=\"fa-solid fa-scroll\"></i> <b>Kỷ lục phiêu lưu</b></div>
            ${createDetailItem('Tổng số lần cao trào', getValue(data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Tổng_số_lần_cao_trào', 0), 'fa-wave-square')}
            ${createDetailItem('Tổng số lần bại trận', getValue(data, 'Ghi_chép.Tổng_số_lần_thất_bại', 0), 'fa-heart-crack')}
            ${createDetailItem(recordsHeader, bossesHtml, recordsIcon)}
            ${createDetailItem(childrenLabel, childrenDisplayHtml, 'fa-baby')} 
        </div>`;
    };

    // --- Render thanh nhịp tim cộng hưởng (EKG) ---
    const renderEKGMonitor = (data) => {
        const current = getValue(data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', 0);
        const threshold = getValue(data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Ngưỡng_cao_trào', 100);
        const ratio = Math.min(1, current / threshold); 
        const percent = ratio * 100;
        let beatClass = 'beating'; let fillClass = '';

        if (current >= threshold) { beatClass = 'beating-fast'; fillClass = 'critical'; }
        else if (ratio >= 0.7) { beatClass = 'beating-fast'; }

        return `
        <div class="ekg-wrapper">
            <div class="ekg-heart-box"><i class="fa-solid fa-heart ekg-icon ${beatClass}"></i></div>
            <div style="display:flex; flex-direction:column; gap:4px; width:100%;">
                <div style="display:flex; justify-content:space-between; font-size:0.8em; color:var(--text-secondary); padding:0 2px;">
                    <span>PLEASURE</span><span>${Math.round(percent)}%</span>
                </div>
                <div class="ekg-bar-container"><div class="ekg-bar-fill ${fillClass}" style="width: ${percent}%"></div></div>
            </div>
            <div class="ekg-data">${Math.round(current)}</div>
        </div>`;
    };

    // --- Logic hiển thị Bảng điều khiển chính ---
    const renderStatusPanel = (data) => {
        if (!data || !getValue(data, 'Trạng_thái_hệ_thống.Đã_tạo_xong_nhân_vật_chính')) return `<div class='status-card' style='text-align:center; padding:20px;'>Đang chờ kết nối...</div>`;

        // 1. Giải nén biến số
        const personality = getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách', 'Lương_thiện');
        const isFallen = personality === 'Sa_ngã';
        const corruption = getValue(data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', 0);
        const levelState = getValue(data, 'Tiến_trình.Giai_đoạn', 'Giai_đoạn_chuyển_cảnh');

        // 2. Tiêu đề và Đánh giá trạng thái
        const isTransformed = getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', false);
        const magicName = getValue(data, 'Nhân_vật_chính.Thông_tin_cơ_bản.Tên_ma_pháp_thiếu_nữ');
        const realName = getValue(data, 'Nhân_vật_chính.Thông_tin_cơ_bản.Họ_tên');
        const currentName = (isTransformed && magicName) ? magicName : (realName || 'Nhân vật chính');
        const prefixText = isFallen ? 'Ma pháp thiếu nữ sa ngã' : 'Ma pháp thiếu nữ';

        const currentEvents = getValue(data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});
        const isCorrupting = currentEvents['Ma pháp thiếu nữ ác đọa'] || currentEvents['Điểm tới hạn sa ngã'];
        const headerTitle = `<span class='${isCorrupting ? 'corrupt-active' : ''}'>${prefixText} ${currentName}</span>`;

        // 3. Định nghĩa nhãn UI
        const hpLabel = isFallen ? 'Độ bền' : 'Thể lực';
        const mpLabel = isFallen ? 'Dục lực' : 'Ma lực';
        const corruptionLabel = isFallen ? 'Sự ban phước' : 'Sự xói mòn';
        const corruptionIcon = isFallen ? 'fa-crown' : 'fa-biohazard';
        const ultimateLabel = isFallen ? 'Tích lũy dục vọng' : 'Tích lũy ý chí';
        const ultimateIcon = isFallen ? 'fa-moon' : 'fa-sun';

        const tab1Label = isFallen ? 'Dấu ấn' : 'Hồ sơ';
        const tab2Label = isFallen ? 'Thân xác' : 'Cơ thể';
        const tab3Label = isFallen ? 'Chiến quả' : 'Ghi chép';
        const bodyTabIcon = isFallen ? 'fa-venus-mars' : 'fa-dna';
        const recordsTabIcon = isFallen ? 'fa-trophy' : 'fa-book-medical';

        // 4. Chủ đề động
        let themeClass = 'theme-pure';
        if (isFallen) { themeClass = 'theme-fallen-core'; }
        else if (corruption > 65) { themeClass = 'theme-eroded'; }
        let cardClass = `status-card ${themeClass}`;
        if (getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy', 0) >= 100 || getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế', 0) >= 100) cardClass += ' state-ultimate-ready';
        else if (getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', 100) <= 35) cardClass += ' state-danger';

        // 5. Khu vực ngữ cảnh (Chiến đấu/Chuyển cảnh)
        let contextualHtml = '';
        if (levelState === 'Chuẩn_bị_chiến_đấu' || levelState === 'Vòng_đấu_chiến_đấu') {
            const bossName = getValue(data, 'Thế_giới.Màn_chơi_hiện_tại.Tên', 'Chưa_rõ');
            let statusDisplay;
            if (levelState === 'Chuẩn_bị_chiến_đấu') {
                const bossThemes = getValue(data, 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', []).filter(t => t !== '$__META_EXTENSIBLE__$');
                let themesHtml = (bossThemes.length > 0) ? `<div class='boss-themes'><i class='fa-solid fa-tags'></i> ${bossThemes.join(' / ')}</div>` : '';
                statusDisplay = `<div class="intermission-status"><div style="font-size:0.8em; color:var(--text-secondary)">Đã nhận diện mục tiêu</div><div class='main-status' style='color: var(--combat-color);'>${bossName}</div>${themesHtml}</div>`;
            } else { // Vòng chiến đấu
                const bossToughness = getValue(data, 'Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', null);
                let bossHealthBar = '';

                // Cấp độ đe dọa
                const threatLv = getValue(data, 'Thế_giới.Cấp_độ_đe_dọa', 1);
                const threatConfig = isFallen 
                    ? { 1: { t: 'Đồ chơi', c: '#a8d8ea' }, 2: { t: 'Con mồi', c: '#bb9af7' }, 3: { t: 'Kẻ địch mạnh', c: '#f7768e' } }
                    : { 1: { t: 'Kẻ quấy rối', c: '#9ece6a' }, 2: { t: 'Kẻ xâm phạm', c: '#e0af68' }, 3: { t: 'Kẻ chi phối', c: '#f87171' } };
                const tInfo = threatConfig[threatLv] || { t: 'Mối đe dọa chưa rõ', c: '#787c99' };
                const threatHtml = `<span style="color:${tInfo.c}; font-weight:bold; padding:2px 6px; background:rgba(0,0,0,0.2); border-radius:4px; margin-left:6px; font-size:0.8em;">Lv.${threatLv} ${tInfo.t}</span>`;

                if (bossToughness !== null) {
                    const bossHpPct = Math.max(0, Math.min(100, bossToughness));
                    bossHealthBar = `
                    <div class='progress-item'>
                        <div class='progress-label'><span><i class='fa-solid fa-shield-virus'></i> <span>Độ bền (Boss)</span></span><span class='progress-value'>${bossToughness}/100</span></div>
                        <div class='progress-bar' style="position:relative; overflow:visible; background:rgba(0,0,0,0.6);">
                            <div class="boss-phase-marker" style="left: 30%;" data-phase="P3"></div>
                            <div class="boss-phase-marker" style="left: 70%;" data-phase="P2"></div>
                            <div class='progress-fill' style='width: ${bossHpPct}%; background: var(--combat-color); position:relative; z-index:1;'></div>
                        </div>
                    </div>`;
                }
                const posture = getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại', 'Đang_chiến_đấu');
                const postureMap = isFallen ? { 'Đang_chiến_đấu': 'Đang săn lùng', 'Bất_lợi': 'Đang tận hưởng' } : { 'Đang_chiến_đấu': 'Đang chiến đấu', 'Bất_lợi': 'Bất lợi' };
                const bossState = getValue(data, 'Thế_giới.Màn_chơi_hiện_tại.Trạng_thái_Boss', 'Nguyên_vẹn');
                const bossThemes = getValue(data, 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', []).filter(t => t !== '$__META_EXTENSIBLE__$');
                const bossThemeHtml = (bossThemes.length > 0) ? `<div class='side-theme'>${bossThemes.join(' / ')}</div>` : '';

                let combatLogHtml = '';
                const lastCombatLog = getValue(data, 'Nhân_vật_chính.Chiến_đấu_tạm_thời.Nhật_ký_chiến_đấu_hiện_tại', 'Không');
                if (lastCombatLog && lastCombatLog !== 'Không') { 
                    const parts = lastCombatLog.split('|'); 
                    const resultText = parts[0] || 'Kiểm định'; 
                    const isFailure = resultText.includes('Thất bại') || resultText.includes('Quấn lấy'); 
                    combatLogHtml = `<div class=\"combat-log-display\"><div><b>Báo cáo chiến trận: <span class=\"${isFailure ? 'log-failure' : 'log-success'}\">${resultText.replace('Kết quả:','')}</span></b></div><small style=\"opacity: 0.8;\">${parts.slice(1).join(' | ')}</small></div>`; 
                }
                statusDisplay = `<div class='battle-status-grid'><div class='status-side player-side'><div class='side-label'>Người chơi</div><div class='side-main'>${currentName}</div><div class='side-status-container'><span class='side-status-tag'>${postureMap[posture] || posture}</span></div></div><div class='status-side enemy-side'><div class='side-label'>Kẻ thù ${threatHtml}</div><div class='side-main'>${bossName}</div><div class='side-status-container'><span class='side-status-tag' style='background:var(--combat-color)'>${bossState}</span></div>${bossThemeHtml}</div></div>${bossHealthBar}${combatLogHtml}`;
            }
            contextualHtml = `<div class=\"context-box\">${statusDisplay}</div>`;
        } else {
            // Xử lý sự kiện chuyển cảnh
            const eventName = getValue(data, 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Tên', 'Không');
            if (eventName && eventName !== 'Không') {
                const eventThemes = getValue(data, 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Chủ_đề_cốt_lõi', []).filter(t => t !== '$__META_EXTENSIBLE__$').join(' / ');
                contextualHtml = `
                <div class=\"context-box intermission-status\" style=\"border-left: 4px solid var(--pleasure-color); background: linear-gradient(90deg, rgba(233,30,99,0.1), transparent);\">
                    <div style=\"color:var(--pleasure-color); font-weight:bold; font-size:0.9em; margin-bottom:5px;\">
                        <i class=\"fa-solid fa-triangle-exclamation\"></i> Sự kiện H chuyển cảnh
                    </div>
                    <div class='main-status' style=\"font-size:1.2em; line-height:1.3;\">${eventName}</div>
                    <div class='sub-status' style=\"color:var(--text-secondary); margin-top:5px; font-size:0.85em;\"> <i class=\"fa-solid fa-tags\"></i> ${eventThemes} </div>
                </div>`;
            } else {
                const stateText = { 'Giai_đoạn_chuyển_cảnh': (isFallen ? '🍷 Thời gian nghỉ' : '☕ Thời gian nghỉ'), 'Vòng_đấu_kết_thúc': '✨ Lượt kết liễu', 'Chiến_thắng': '🏆 Chiến thắng', 'Thất_bại': '💔 Kiệt sức bại trận', 'Xử_lý_sau_trận': '🧹 Xử lý sau trận' }[levelState] || levelState;
                contextualHtml = `<div class=\"context-box intermission-status\"><div class='main-status'>${stateText}</div><div class='sub-status'>${getValue(data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Động_thái_sinh_lý_hiện_tại')}</div></div>`;
            }
        }

        const ekgMonitorHtml = (typeof renderEKGMonitor === 'function') ? renderEKGMonitor(data) : '';

        const progressHtml = `<div class=\"progress-stack\">
            <div class='stack-header'>Tài nguyên cơ bản</div>
            ${renderProgressItem({ path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', label: hpLabel, options: { icon: 'fa-solid fa-heart', color: 'var(--hp-color)', max: getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Tối_đa', 100) } }, data, isFallen)}
            ${renderProgressItem({ path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', label: mpLabel, options: { icon: 'fa-solid fa-wand-magic-sparkles', color: 'var(--mp-color)', max: getValue(data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Tối_đa', 100) } }, data, isFallen)}
            <div class='stack-header'>Tinh thần và Giác quan</div>
            ${ekgMonitorHtml}
            ${renderProgressItem({ path: 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', label: corruptionLabel, options: { icon: `fa-solid ${corruptionIcon}`, color: 'var(--corruption-color)' } }, data, isFallen)}
            <div class='stack-header'>Kỹ năng tối thượng</div>
            <div class='progress-item'>${renderProgressItem({ path: isFallen ? 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế' : 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy', label: ultimateLabel, options: { icon: `fa-solid ${ultimateIcon}`, color: 'var(--ultimate-color)' } }, data, isFallen)}</div>
        </div>`;

        const tabbedHtml = `
            <div class=\"tab-container\">
                <button class=\"tab-btn\" data-target=\"panel-character\"><i class=\"fa-solid fa-address-card\"></i> ${tab1Label}</button>
                <button class=\"tab-btn\" data-target=\"panel-body\"><i class=\"fa-solid ${bodyTabIcon}\"></i> ${tab2Label}</button>
                <button class=\"tab-btn\" data-target=\"panel-records\"><i class=\"fa-solid ${recordsTabIcon}\"></i> ${tab3Label}</button>
            </div>
            <div class=\"content-container\">
                <div id=\"panel-character\" class=\"tab-content\">${renderCharacterInfo(data, personality)}</div>
                <div id=\"panel-body\" class=\"tab-content\">${renderBodyStatus(data)}</div>
                <div id=\"panel-records\" class=\"tab-content\">${renderRecords(data, personality)}</div>
            </div>`;

        return `<div class='${cardClass}'>
            <div class=\"panel-left\">
                <div class=\"card-header\"><h2>${headerTitle}</h2>                   </div>
                ${contextualHtml}
                ${progressHtml}
            </div>
            <div class=\"panel-right\">${tabbedHtml}</div>
        </div>`;
    };

    const renderPanelWithData = (stat_data) => {
        if (typeof hideDynamicTooltip === 'function') {
            hideDynamicTooltip(); 
            const oldTooltips = document.querySelectorAll('.custom-tooltip-dynamic');
            oldTooltips.forEach(el => el.remove());
        }
        const container = document.getElementById('status-card-container');
        if (!container) return;
        try {
            const newHTML = renderStatusPanel(stat_data);
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = newHTML;
            const newContent = tempDiv.firstChild;
            if (newContent && newContent.querySelector) {
                const newActiveButton = newContent.querySelector(`[data-target="${lastActiveTabId}"]`);
                if (newActiveButton) newActiveButton.classList.add('active');
                const newActivePanel = newContent.querySelector(`#${lastActiveTabId}`);
                if (newActivePanel) newActivePanel.classList.add('active');
            }
            if (container.firstChild) { updateDOM(container.firstChild, newContent); } 
            else { if(newContent) container.appendChild(newContent); }
        } catch (error) {console.error('Lỗi khi render Panel:', error); container.innerHTML = `<div class='status-card' style='color:var(--combat-color);'>Lỗi hiển thị: ${error.message}</div>`; } 
    };

    function getMvuInstance() { try { return window.Mvu || (window.parent && window.parent.Mvu) || (window.top && window.top.Mvu) || null; } catch (e) { return null; } }

    // --- Logic Tooltip trôi nổi ---
    const setupTooltips = () => {
        let activeTooltip = null;
        const showTip = (target) => {
            const tooltip = target.querySelector('.custom-tooltip');
            if (!tooltip) return;
            tooltip.classList.add('active');
            activeTooltip = tooltip;
            const targetRect = target.getBoundingClientRect();
            const tipRect = tooltip.getBoundingClientRect();
            let top = targetRect.top + (targetRect.height / 2) - (tipRect.height / 2);
            let left = targetRect.right + 15; 
            if (top + tipRect.height > window.innerHeight - 10) { top = window.innerHeight - tipRect.height - 10; }
            if (top < 10) top = 10;
            if (left + tipRect.width > window.innerWidth - 10) { left = targetRect.left - tipRect.width - 15; }
            tooltip.style.top = top + 'px';
            tooltip.style.left = left + 'px';
        };
        const hideTip = () => { if (activeTooltip) { activeTooltip.classList.remove('active'); activeTooltip = null; } };
        document.addEventListener('mouseover', (e) => { const trigger = e.target.closest('.has-tooltip'); if (trigger) showTip(trigger); });
        document.addEventListener('mouseout', (e) => { const trigger = e.target.closest('.has-tooltip'); if (trigger) hideTip(); });
        window.addEventListener('scroll', hideTip, true);
    };

    // Khởi tạo
    setupTooltips();
    const init = () => {
        const Mvu = window.Mvu || (window.parent && window.parent.Mvu) || (window.top && window.top.Mvu);
        if (Mvu && Mvu.events) {
            console.log("[PC Status] Tìm thấy MVU, đang đăng ký lắng nghe sự kiện gốc.");
            document.addEventListener(Mvu.events.VARIABLE_UPDATE_ENDED, (e) => {
                if (e.detail && e.detail.stat_data) { renderPanelWithData(e.detail.stat_data); }
            });
            (async () => { 
                try { 
                    if (typeof getChatMessages !== 'undefined') {
                        const msgs = await getChatMessages(getCurrentMessageId());
                        const data = msgs[0]?.data?.stat_data || Mvu.getMvuData({type:'message', message_id:-1})?.stat_data;
                        renderPanelWithData(data);
                    }
                } catch (e) { console.warn("[PC Status] Tải dữ liệu ban đầu thất bại.", e); } 
            })();
            const container = document.getElementById('status-card-container');
            if (container) {
                container.addEventListener('click', (event) => {
                    const button = event.target.closest('.tab-btn');
                    if (!button || button.classList.contains('active')) return;
                    const targetPanelId = button.dataset.target;
                    const targetPanel = container.querySelector(`#${targetPanelId}`);
                    if (!targetPanel) return;
                    container.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
                    container.querySelectorAll('.tab-content').forEach(panel => panel.classList.remove('active'));
                    button.classList.add('active');
                    targetPanel.classList.add('active');
                    lastActiveTabId = targetPanelId;
                });
            }
        } else {
            setTimeout(init, 500);
        }
    };

    if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', init); } else { init(); }

    // --- Logic hiển thị Bảng điều khiển GM ---
    window.toggleGM = () => {
        const p = document.getElementById('gm-panel');
        if (p) {
            if (!p.classList.contains('show')) {
                p.style.display = 'flex'; 
                requestAnimationFrame(() => {
                    p.classList.add('show');
                    window.renderGM();
                    if(_currentMvuData) {
                        _gmSnapshot = JSON.parse(JSON.stringify(_currentMvuData));
                        showToast("Đã tạo Snapshot", "#save-status");
                    }
                });
            } else {
                p.classList.remove('show');
                setTimeout(() => p.style.display = 'none', 250);
            }
        }
    };

    window.toggleGMMaximize = () => {
        const p = document.getElementById('gm-panel');
        const icon = document.getElementById('gm-max-icon');
        if (p) {
            p.classList.toggle('maximized');
            icon.className = p.classList.contains('maximized') ? "fa-regular fa-clone" : "fa-regular fa-square";
        }
    };

    window.switchGmTab = (btn, targetId) => {
        document.querySelectorAll('.gm-tab').forEach(t => t.classList.remove('active'));
        btn.classList.add('active');
        document.querySelectorAll('.gm-content').forEach(c => c.classList.remove('active'));
        document.getElementById(targetId).classList.add('active');
    };

    const showToast = (msg, selector) => {
        const el = document.querySelector(selector);
        if(el) { el.innerText = msg; el.style.opacity = 1; setTimeout(() => el.style.opacity = 0, 2000); }
    };

    const setInp = (id, val) => {
        const el = document.getElementById(id);
        if(el && document.activeElement !== el) el.value = (typeof val === 'number') ? Math.round(val) : val;
    };
    const setTxt = (id, val) => { const el = document.getElementById(id); if(el) el.innerText = val; };

    window.renderGM = async () => {
        try {
            const Mvu = window.Mvu || window.parent?.Mvu || window.top?.Mvu;
            if (!Mvu) return;
            const wrapper = Mvu.getMvuData({ type: 'message', message_id: -1 });
            if (!wrapper) return;
            _currentMvuData = wrapper.stat_data || wrapper;
            const d = _currentMvuData;

            const phase = getDeep(d, 'Tiến_trình.Giai_đoạn', 'Giai_đoạn_chuyển_cảnh');
            const isCombat = ['Vòng_đấu_chiến_đấu', 'Chuẩn_bị_chiến_đấu', 'Vòng_đấu_kết_thúc'].includes(phase);
            const isIntermission = (phase === 'Giai_đoạn_chuyển_cảnh');

            document.getElementById('panel-combat-control').style.display = isCombat ? 'block' : 'none';
            document.getElementById('panel-intermission-control').style.display = isIntermission ? 'block' : 'none';
            setTxt('current-phase-display', phase);
            setInp('phase-selector', phase);

            const isHEvent = (isIntermission && getDeep(d, 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Tên', 'Không') !== 'Không');
            const targetPath = (isIntermission && !isHEvent) ? 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Chủ_đề_cốt_lõi' : 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi';
            setTxt('theme-target-label', (isIntermission && !isHEvent) ? "Mục tiêu: Sự kiện chuyển cảnh" : "Mục tiêu: Chiến đấu/Màn chơi");

            const themes = getDeep(d, targetPath, []);
            const validThemes = Array.isArray(themes) ? themes.filter(t => t !== '$__META_EXTENSIBLE__$') : [];
            document.getElementById('theme-tags-container').innerHTML = validThemes.map(t => `
                <div class="theme-tag ${isIntermission ? 'h-event' : ''}">
                    ${t} <span class="del" onclick="removeTheme('${targetPath}', '${t}')">×</span>
                </div>`).join('') || '<span style="opacity:0.5; font-style:italic;">Không chủ đề</span>';

            setInp('inp-hp', getDeep(d, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', 0));
            setInp('inp-mp', getDeep(d, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', 0));
