        const cleanThemes = heventThemes.filter(t => t && t !== '$__META_EXTENSIBLE__$');
        const isPreLocked = (!getDeep(d, 'Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh', true) && heventName === 'Không' && cleanThemes.length > 0);

        let targetName = 'EVENT：Kích hoạt ép buộc', targetThemes = cleanThemes;
