 */

// =================================================================================
// --- 1. Cấu hình toàn cục & Cây trạng thái ---
// =================================================================================

const SCRIPT_NAME = 'Kịch_bản_giám_sát_MVU';
const SCRIPT_VERSION = 'v22.1';

const KINK_LEVEL_THRESHOLDS = [
    { level: 4, xp_needed: 1000 }, { level: 3, xp_needed: 500 },
    { level: 2, xp_needed: 250 }, { level: 1, xp_needed: 100 },
    { level: 0, xp_needed: 0 }
];

const scriptState = {
    initialized: false,
    retryCount: 0,
    maxRetries: 10,
    listeners: { onVariableUpdateEnded: null },
    previousData: null,
    turnCounters: {
        finisher: 0,
        victory: 0,
        defeatPersistence: 0
    }
};

// =================================================================================
// --- 2. Hàm công cụ hỗ trợ ---
// =================================================================================

function getMvuInstance() {
    try { return window.Mvu || window.parent?.Mvu || window.top?.Mvu || null; } 
    catch (e) { console.warn(`[${SCRIPT_NAME}] Lỗi khi truy cập thể hiện MVU:`, e); return null; }
}

function applyAdd(variables, path, delta) {
    const fullPath = `stat_data.${path}`;
    const currentValue = parseFloat(_.get(variables, fullPath, 0)) || 0;
    const deltaValue = parseFloat(delta) || 0;
    if (typeof currentValue === 'number' && typeof deltaValue === 'number') {
        _.set(variables, fullPath, currentValue + deltaValue);
    }
}

function applyAssign(variables, path, value) {
    const fullPath = `stat_data.${path}`;
    let targetArray = _.get(variables, fullPath);
    if (!Array.isArray(targetArray)) return;
    const alreadyExists = targetArray.some(item => _.isEqual(item, value));
    if (alreadyExists) return;
    const metaTag = '$__META_EXTENSIBLE__$';
    const metaIndex = targetArray.indexOf(metaTag);
    if (metaIndex > -1) {
        targetArray.splice(metaIndex, 0, value);
    } else {
        targetArray.push(value);
    }
}

// =================================================================================
// --- 3. Module bảo vệ & dọn dẹp dữ liệu ---
// =================================================================================

function clampStatValues(variables) {
    const maxHP = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Tối_đa', 100);
    const maxMP = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Tối_đa', 100);
    const clampConfigs = [
        { path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', min: 0, max: maxHP },
        { path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', min: 0, max: maxMP },
        { path: 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', min: 0, max: 9999 },
        { path: 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', min: 0, max: 100 },
        { path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy', min: 0, max: 100 },
        { path: 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế', min: 0, max: 100 },
        { path: 'Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', min: 0, max: 100 }
    ];
    clampConfigs.forEach(config => {
        const value = _.get(variables.stat_data, config.path);
        if (typeof value === 'number') {
            const clampedValue = Math.round(Math.max(config.min, Math.min(config.max, value)));
            if (clampedValue !== value) {
                _.set(variables, `stat_data.${config.path}`, clampedValue);
            }
        }
    });
}

function validateAndCorrectData(variables) {
    const validationMap = {
        'Tiến_trình.Giai_đoạn': { valid: ['Giai_đoạn_tạo_nhân_vật', 'Nghỉ_ngơi_chuyển_cảnh', 'Chuẩn_bị_chiến_đấu', 'Lượt_chiến_đấu', 'Lượt_kết_liễu', 'Chiến_thắng', 'Thất_bại', 'Xử_lý_sau_trận_chiến'], default: 'Nghỉ_ngơi_chuyển_cảnh' },
        'Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại': { valid: ['Không_chiến_đấu', 'Đang_chiến_đấu', 'Bất_lợi', 'Kiệt_sức_chờ_nhục', 'Yếu_ớt_sau_trận'], default: 'Không_chiến_đấu' }
    };
    for (const path in validationMap) {
        const value = _.get(variables.stat_data, path);
        const config = validationMap[path];
        if (value && !config.valid.includes(value)) {
            _.set(variables, `stat_data.${path}`, config.default);
        }
    }
}

// Bảo trì mảng và sửa lỗi thẻ: Xóa trùng lặp, sửa lỗi, bổ sung thẻ extensible
function maintainExtensibleArrays(variables) {
    const targetPaths = ['Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi'];
    targetPaths.forEach(path => {
        let arr = _.get(variables.stat_data, path);
        // Sửa lỗi kiểu dữ liệu
        if (!Array.isArray(arr)) {
            arr = arr ? [arr] : [];
        }
        // Dọn dẹp và xóa trùng lặp
        const cleanArr = arr.filter(item => item !== '$__META_EXTENSIBLE__$');
        let uniqueArr;
        if (path === 'Ghi_chép.Boss_đã_đánh_bại') {
            uniqueArr = _.uniqBy(cleanArr, (item) => (typeof item === 'object' && item.Tên) ? item.Tên : item);
        } else {
            uniqueArr = _.uniq(cleanArr);
        }
        uniqueArr.push('$__META_EXTENSIBLE__$');
        // Phát hiện thay đổi
        if (!_.isEqual(arr, uniqueArr)) {
            _.set(variables, `stat_data.${path}`, uniqueArr);
        }
    });
}

function processSemenCleanup(variables, prev_stat_data) {
    const amountPath = 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn';
    const sourcePath = 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Nguồn_gốc';
    const currentAmount = parseInt(_.get(variables.stat_data, amountPath, 0), 10) || 0;
    const currentSources = _.get(variables.stat_data, sourcePath, {});

    // Nếu lượng tồn bằng 0, làm trống nguồn gốc
    if (currentAmount <= 0 && Object.keys(currentSources).length > 0) {
        _.set(variables, `stat_data.${sourcePath}`, {});
    }
}

function processCombatLogCleanup(variables, prev_stat_data) {
    if (!prev_stat_data) return;
    const logPath = 'Nhân_vật_chính.Chiến_đấu_tạm_thời.Nhật_ký_chiến_đấu_hiện_tại';
    const isInCombat = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn') === 'Lượt_chiến_đấu';
    if (!isInCombat) {
        if (_.get(variables.stat_data, logPath) !== 'Không') _.set(variables, `stat_data.${logPath}`, 'Không');
        return;
    }
    const currentLog = _.get(variables.stat_data, logPath);
    const previousLog = _.get(prev_stat_data, logPath);
    if (currentLog && currentLog !== 'Không' && currentLog === previousLog) {
        _.set(variables, `stat_data.${logPath}`, 'Không');
    }
}

function resetTemporaryBuffs(variables) {
    const buffPath = 'Nhân_vật_chính.Chiến_đấu_tạm_thời.Giá_trị_tăng_cường_tạm_thời'; // Hoặc Giá_trị_kiểm_định_người_chơi_mỗi_lượt
    if (_.get(variables.stat_data, buffPath, 0) !== 0) {
        _.set(variables, `stat_data.${buffPath}`, 0);
    }
}

/**
 * Hàm chính của module bảo vệ dữ liệu
 */
function guardAndSanitizeData(variables) {
    // Ép kiểu boolean
    const booleanPaths = ['Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', 'Trạng_thái_hệ_thống.Đã_tạo_xong_nhân_vật_chính', 'Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh'];
    booleanPaths.forEach(path => {
        const val = _.get(variables.stat_data, path);
        if (val === 'true') _.set(variables, `stat_data.${path}`, true);
        if (val === 'false') _.set(variables, `stat_data.${path}`, false);
    });

    validateAndCorrectData(variables);
    clampStatValues(variables);
    maintainExtensibleArrays(variables);
    processSemenCleanup(variables, scriptState.previousData);
    processCombatLogCleanup(variables, scriptState.previousData);
    resetTemporaryBuffs(variables);
    const currentPhase = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn');
    const bossName = _.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Tên', 'Không');
    // Khi đang ở giai đoạn nghỉ ngơi và chưa tạo Boss chính thức
    if (currentPhase === 'Nghỉ_ngơi_chuyển_cảnh' && (bossName === 'Không' || bossName === 'Cảnh_báo_mối_đe_dọa')) {
        const currentThemes = _.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', []);
        const validThemes = (Array.isArray(currentThemes) ? currentThemes : []).filter(t => t !== '$__META_EXTENSIBLE__$');

        // Nếu không có chủ đề cốt lõi nào, tự động rút một chủ đề
        if (validThemes.length === 0) {
            const themePool = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Nhóm_chủ_đề_tạo_Boss', []).filter(t => t !== '$__META_EXTENSIBLE__$');
            if (themePool.length > 0) {
                const preLockedTheme = _.sample(themePool);
                _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', [preLockedTheme, '$__META_EXTENSIBLE__$']);
                console.log(`[${SCRIPT_NAME}] 📡 Cơ chế tự phục hồi kích hoạt: Tự động nạp chủ đề đe dọa ban đầu -> ${preLockedTheme}`);
            }
        }
    }
}

