/**
 * Xử lý sau cùng: Hệ thống kết toán cao trào
 */
function processOrgasmImmediate(variables) {
    let pleasure = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', 0), 10) || 0;
    let threshold = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Ngưỡng_cao_trào', 100), 10) || 100;
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});

    // 1. Khóa kích hoạt: Tràn chỉ số + Không có sự kiện -> Treo sự kiện, chưa tính toán số liệu (chờ lượt sau)
    if (pleasure >= threshold && !currentEvents['Sự_kiện_cao_trào']) {
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_cao_trào', true);
        return; 
    }

    // 2. Khóa kết toán: Tràn chỉ số + Có sự kiện -> Đã có cờ hiệu, bắt đầu kết toán
    if (pleasure >= threshold) {
        console.log(`[${SCRIPT_NAME}] ♻️ Kết thúc lượt, thực hiện kết toán điểm cao trào.`);
        const isInCombat = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn') === 'Lượt_chiến_đấu';
        const personality = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách', 'Lương_thiện');
        let loopCount = 0;

        // Trừ điểm khoái cảm cho đến khi thấp hơn ngưỡng
        while (pleasure >= threshold) {
            pleasure -= threshold;
            loopCount++;
            // Phạt trong chiến đấu (Tuyến Lương thiện)
            if (isInCombat && personality === 'Lương_thiện') {
                applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', -_.random(5, 10));
                applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', -_.random(10, 20));
                applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', _.random(8, 15));
                threshold += 20; // Cơ chế nâng ngưỡng
                _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Ngưỡng_cao_trào', threshold);
            }
        }

        // Cập nhật số liệu sau kết toán
        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', pleasure);
        if (loopCount > 0) applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Tổng_số_lần_cao_trào', loopCount);
    }
}

function processDailyReset(variables, prev_stat_data) {
    if (!prev_stat_data) return;
    const currentDay = _.get(variables.stat_data, 'Thế_giới.Thời_gian');
    const previousDay = _.get(prev_stat_data, 'Thế_giới.Thời_gian');

    if (typeof currentDay === 'number' && typeof previousDay === 'number' && currentDay > previousDay) {
        // Reset ngưỡng
        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Ngưỡng_cao_trào', 100);

        const personality = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách');
        const currentCorruption = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', 0);

        // Giảm tự nhiên nếu đi tuyến Sa ngã
        if (personality === 'Sa_ngã' && currentCorruption > 20) {
            applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', -_.random(5, 10));
        }
        // Phục hồi tự nhiên tuyến Lương thiện
        if (personality === 'Lương_thiện' && currentCorruption > 0 && currentCorruption < 90) {
             applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', -2);
        }
    }
}

function processCorruptionOnInsemination(variables, prev_stat_data) {
    if (!prev_stat_data || _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách') !== 'Lương_thiện' || _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn') !== 'Lượt_chiến_đấu') return;
    const currentSemen = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
    const previousSemen = _.get(prev_stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);

    if (currentSemen - previousSemen > 0) {
        const corruptionGain = _.random(3, 8) + Math.floor((currentSemen - previousSemen) / 50) * _.random(1, 3);
        applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', corruptionGain);
    }
}

function processConceptionChance(variables, prev_stat_data) {
    if (!prev_stat_data || _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Trạng_thái_thụ_thai') !== 'Chưa_thụ_thai') return;

    const currentSemen = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
    const previousSemen = _.get(prev_stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
    const delta = currentSemen - previousSemen;

    // Chỉ tiêm vào trên 5ml mới có nguy cơ thụ thai (Tỉ lệ 30%)
    if (delta > 5 && Math.random() < 0.3) {

        const currentSources = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Nguồn_gốc', {});
        const prevSources = _.get(prev_stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Nguồn_gốc', {});

        const newKeys = Object.keys(currentSources).filter(k => 
            k !== '$meta' && k !== '$__META_EXTENSIBLE__$' && !prevSources[k]
        );

        const allKeys = Object.keys(currentSources).filter(k => 
            k !== '$meta' && k !== '$__META_EXTENSIBLE__$'
        );

        let sourceEnemy = 'Ma_vật_chưa_rõ';
        if (newKeys.length > 0) {
            sourceEnemy = _.sample(newKeys);
        } else if (allKeys.length > 0) {
            sourceEnemy = _.sample(allKeys);
        }

        console.log(`[${SCRIPT_NAME}] ❤️ Vượt qua đánh giá thụ thai! Lượng tiêm: ${delta}, Kẻ gây ra: ${sourceEnemy}`);

        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Trạng_thái_thụ_thai', 'Đang_thụ_thai');
        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Thông_tin_mang_thai.Nguồn_gốc_mang_thai', sourceEnemy);
        applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_tử_cung.Thông_tin_mang_thai.Bộ_đếm_thai_kỳ', 1);

        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_thụ_thai', true);
    }
}

function processNewModifications(variables, prev_stat_data) {
    if (!prev_stat_data) return;
    const modsPath = 'Nhân_vật_chính.Cải_tạo_cơ_thể_vĩnh_viễn';
    const currentMods = _.get(variables.stat_data, modsPath, {});
    const previousMods = _.get(prev_stat_data, modsPath, {});
    const template = { "Bộ_phận": "Chờ_thiết_lập", "Chi_tiết": "Chờ_thiết_lập", "Nguồn_gốc": "Chưa_rõ" };
    const newKeys = _.difference(Object.keys(currentMods), Object.keys(previousMods));
    for (const key of newKeys) {
        if (key === '$meta') continue;
        if (_.isObject(currentMods[key])) {
            _.set(variables, `stat_data.${modsPath}.${key}`, _.defaults({}, currentMods[key], template));
        }
    }
}

function processKinkXpOnOrgasm(variables, prev_stat_data) {
    if (!prev_stat_data) return;
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});
    const previousEvents = _.get(prev_stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {}); 
    if (!currentEvents['Sự_kiện_cao_trào'] || previousEvents['Sự_kiện_cao_trào']) return;

    if (_.get(variables.stat_data, 'Tiến_trình.Giai_đoạn') === 'Lượt_chiến_đấu') {
        const activeKinks = _.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', []).filter(theme => theme !== '$__META_EXTENSIBLE__$');
        if (activeKinks.length > 0) {
            const xpGain = _.random(25, 40);
            activeKinks.forEach(kinkName => {
                const kinkPath = `Nhân_vật_chính.Trạng_thái_khoái_cảm.Sở_thích_tình_dục.${kinkName}.Kinh_nghiệm`;
                if (_.has(variables.stat_data, kinkPath)) { applyAdd(variables, kinkPath, xpGain); }
            });
        }
    }
}

function processCharacterGrowth(variables, prev_stat_data) {
    const currentPhase = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn');
    if (currentPhase === 'Chiến_thắng') {
        const events = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {}); 
        if (events['Trưởng_thành_năng_lực_nhân_vật_chính']) return; 

        console.log(`[${SCRIPT_NAME}] ✅ Kích hoạt kết toán trưởng thành sau chiến đấu`);
        const randomStrengthGain = _.random(2, 6);
        const hpMpGain = 5;

        applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_cơ_bản', randomStrengthGain);
        applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Tối_đa', hpMpGain);
        applyAdd(variables, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Tối_đa', hpMpGain);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Trưởng_thành_năng_lực_nhân_vật_chính', true);
    }
}

function processKinkExperienceAndLeveling(variables, prev_stat_data) {
    if (!prev_stat_data) return;
    const kinksPath = 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Sở_thích_tình_dục';
    const currentKinks = _.get(variables.stat_data, kinksPath, {});
    const allKinkNames = Object.keys(currentKinks);

    for (const kinkName of allKinkNames) {
        if (kinkName.startsWith('//') || kinkName === '$meta') continue;
        const currentExp = parseInt(_.get(currentKinks[kinkName], 'Kinh_nghiệm', 0), 10) || 0;
        const currentLevel = parseInt(_.get(currentKinks[kinkName], 'Cấp_độ', 0), 10) || 0;

        let calculatedLevel = 0;
        for (const threshold of KINK_LEVEL_THRESHOLDS) {
            if (currentExp >= threshold.xp_needed) { 
                calculatedLevel = threshold.level; 
                break; 
            }
        }
        if (calculatedLevel !== currentLevel) {
            _.set(variables, `stat_data.${kinksPath}.${kinkName}.Cấp_độ`, calculatedLevel);
        }
    }
}

function processCombatResultRegistration(variables, prev_stat_data, resultType) {
    console.log(`[${SCRIPT_NAME}] Ghi nhận kết quả trận đấu: ${resultType}`);
    const bossName = _.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Tên', 'Kẻ_địch_chưa_rõ');
    if (bossName === 'Không' || bossName === 'Kẻ_địch_chưa_rõ') return;

    const coreThemes = _.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', []).filter(t => t && t !== '$__META_EXTENSIBLE__$');
    const timestamp = _.get(variables.stat_data, 'Thế_giới.Thời_gian', 1);

    const recordEntry = { 
        "Tên": bossName, 
        "Chủ_đề_cốt_lõi": coreThemes,
        "Kết_quả": (resultType === 'Chiến_thắng') ? 'WIN' : 'LOSE',
        "Thời_gian": timestamp 
    };
    _.set(variables, ['stat_data', 'Ghi_chép', 'Boss_đã_đánh_bại', bossName], recordEntry);

    if (resultType === 'Chiến_thắng') {
        applyAdd(variables, 'Ghi_chép.Số_lượng_Boss_đã_đánh_bại', 1);
    }
    _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', 0);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại', 'Không_chiến_đấu');
}

function processPersonalityFall(variables, prev_stat_data) {
    const corruption = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', 0);
    const personality = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách', 'Lương_thiện');
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});

    if (personality === 'Lương_thiện' && corruption >= 100) {
        if (!currentEvents['Điểm_tới_hạn_sa_ngã'] && !currentEvents['Ma_pháp_thiếu_nữ_ác_đọa']) {
            _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Điểm_tới_hạn_sa_ngã', true);
        }
    }
}

function processForceUntransform(variables, prev_stat_data) {
    const currentMP = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', 0);
    const isTransformed = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', false);

    if (isTransformed === true && currentMP <= 0) {
        console.log(`[${SCRIPT_NAME}] Cạn kiệt MP. Cưỡng chế hủy biến hình.`);
        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', false);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Cưỡng_chế_hủy_biến_hình', true);
    }
}

function processCapacityAndOverflow(variables, prev_stat_data) {
    const currentAmount = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Thể_dịch_và_bài_tiết.Tinh_dịch_trong_tử_cung.Lượng_tồn', 0);
    const maxCapacity = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Dung_tích_tối_đa', 50);
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});

    if (currentAmount > maxCapacity && !currentEvents['Sự_kiện_tràn_đầy_bên_trong']) {
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_tràn_đầy_bên_trong', true);
    }
}

/**
 * Kết toán tràn trề dung dịch và nâng cao sức chứa
 */
function processCapacityExpansion(variables, prev_stat_data) {
    if (!prev_stat_data) return;

    const prevEvents = _.get(prev_stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});

    // Nếu sự kiện tràn đầy bên trong đã hoàn tất
    if (prevEvents['Sự_kiện_tràn_đầy_bên_trong'] && !currentEvents['Sự_kiện_tràn_đầy_bên_trong']) {
        const capacityPath = 'Nhân_vật_chính.Trạng_thái_sinh_lý.Trạng_thái_âm_đạo.Dung_tích_tối_đa';
        let currentCapacity = parseInt(_.get(variables.stat_data, capacityPath, 50), 10) || 50;

        // Không vượt quá 200ml
        if (currentCapacity < 200) {
            const increaseAmount = _.random(10, 20); 
            const newCapacity = Math.min(200, currentCapacity + increaseAmount);

            _.set(variables, `stat_data.${capacityPath}`, newCapacity);
            console.log(`[${SCRIPT_NAME}] 🌊 Kết toán đầy bên trong đã hoàn tất, cơ thể đã thích nghi. Nâng tối đa: ${currentCapacity}ml -> ${newCapacity}ml`);
        }
    }
}

function processIntermissionEventCleanup(variables, prev_stat_data) {
    const eventCompleted = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh', true);

    // Kiểm soát nhịp độ
    if (prev_stat_data) {
        const prevCompleted = _.get(prev_stat_data, 'Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh', true);
        if (String(eventCompleted) === 'true' && String(prevCompleted) === 'false') {
            _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Đếm_lượt_chuyển_cảnh', 1);
        }
    }

    // Xóa dữ liệu cũ
    if (eventCompleted === true) {
        const eventNamePath = 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Tên';
        const eventThemesPath = 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Chủ_đề_cốt_lõi';
        const currentName = _.get(variables.stat_data, eventNamePath, 'Không');
        const currentThemes = _.get(variables.stat_data, eventThemesPath, []);
        const isDefaultThemes = _.isEqual(currentThemes, ['$__META_EXTENSIBLE__$']);

        if (currentName !== 'Không' || !isDefaultThemes) {
            console.log(`[${SCRIPT_NAME}] Đã dọn dẹp sự kiện H chuyển cảnh.`);
            if (currentName !== 'Không') _.set(variables, `stat_data.${eventNamePath}`, 'Không');
            if (!isDefaultThemes) _.set(variables, `stat_data.${eventThemesPath}`, ['$__META_EXTENSIBLE__$']);
        }
    }
}

/**
 * Gọi tổng hợp các Module cơ chế phản hồi
 */
function processReactiveMechanics(variables) {
    processIntermissionEventCleanup(variables, scriptState.previousData);
    processDailyReset(variables, scriptState.previousData);
    processPersonalityFall(variables, scriptState.previousData);
    processForceUntransform(variables, scriptState.previousData);
    processKinkXpOnOrgasm(variables, scriptState.previousData);
    processCorruptionOnInsemination(variables, scriptState.previousData);
    processConceptionChance(variables, scriptState.previousData);
    processCapacityAndOverflow(variables, scriptState.previousData);
    processCapacityExpansion(variables, scriptState.previousData); 
    processOrgasmImmediate(variables);
    processNewModifications(variables, scriptState.previousData);
    processKinkExperienceAndLeveling(variables, scriptState.previousData);

    const currentPhase = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn');
    const prevPhase = _.get(scriptState.previousData, 'Tiến_trình.Giai_đoạn');

    if (currentPhase === 'Chiến_thắng' && prevPhase !== 'Chiến_thắng') {
        processCombatResultRegistration(variables, scriptState.previousData, 'Chiến_thắng');
    }
    if (currentPhase === 'Thất_bại' && prevPhase !== 'Thất_bại') {
        processCombatResultRegistration(variables, scriptState.previousData, 'Thất_bại');
    }
    processCharacterGrowth(variables, scriptState.previousData);
}

