/**
 * Mô đun kiểm tra các mốc sự kiện
 */
function processMilestoneCheck(variables, prev_stat_data) {
    if (!prev_stat_data) return; 

    // --- A. Kiểm tra Nâng cấp vũ trang (Threshold: 70, 90, 110...) ---
    const prevStr = parseInt(_.get(prev_stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_cơ_bản', 50), 10) || 50;
    const curStr = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_cơ_bản', 50), 10) || 50;

    if (curStr > prevStr) {
        const base = 50;
        const step = 20;
        for (let t = base + step; t <= 300; t += step) {
            if (prevStr < t && curStr >= t) {
                console.log(`[Cột mốc] Sức mạnh vượt qua ${t}! Kích hoạt Nâng cấp vũ trang.`);
                _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_nâng_cấp_vũ_trang', true);
                break; 
            }
        }
    }

    // --- B. Danh tiếng (Threshold: 15 / 45 / 85) ---
    const prevFame = parseInt(_.get(prev_stat_data, 'Danh_tiếng.Độ_nổi_tiếng', 0), 10) || 0;
    const curFame = parseInt(_.get(variables.stat_data, 'Danh_tiếng.Độ_nổi_tiếng', 0), 10) || 0;

    if (curFame > prevFame) {
        let fameTitle = "";
        if (prevFame < 15 && curFame >= 15) fameTitle = "Truyền_thuyết_đô_thị";
        else if (prevFame < 45 && curFame >= 45) fameTitle = "Chủ_đề_nóng_bàn_tán";
        else if (prevFame < 85 && curFame >= 85) fameTitle = "Không_ai_không_biết";

        if (fameTitle) {
            console.log(`[Cột mốc] Danh tiếng thăng cấp thành: ${fameTitle}`);
            _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_nâng_cấp_danh_tiếng', fameTitle);
        }
    }

    // --- C. Đánh thức sở thích tình dục (Lv.3) ---
    const currentEvents = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});

    if (!currentEvents['Sự_kiện_thức_tỉnh_sở_thích']) {
        const kinks = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Sở_thích_tình_dục', {});
        const worldNotes = _.get(variables.stat_data, 'Thế_giới.Ghi_chú_thế_giới_quan', {});

        for (const [kinkName, kinkData] of Object.entries(kinks)) {
            if (kinkName === '$meta' || kinkName === '$__META_EXTENSIBLE__$') continue;

            const level = parseInt(kinkData.Cấp_độ || 0, 10);
            const recordKey = `Ghi_chép_thức_tỉnh_${kinkName}`;

            if (level >= 3 && !worldNotes[recordKey]) {
                console.log(`[Cột mốc] Sở thích [${kinkName}] lần đầu đạt Lv.3! Kích hoạt sự kiện thức tỉnh.`);
                _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_thức_tỉnh_sở_thích', kinkName);
                break; 
            }
        }
    }
}

function initializeNewBattle(variables) {
    _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', 100);
    _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Trạng_thái_Boss', 'Nguyên_vẹn');
    if (_.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Tên') === 'Không') {
        _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Tên', 'Mối_đe_dọa_chưa_rõ');
    }
}

function processPlayerStateMachine(variables) {
    const hp = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', 100), 10) || 0;
    const posturePath = 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại';
    const currentPosture = _.get(variables.stat_data, posturePath);
    let newPosture = null;
    if (hp > 35 && currentPosture === 'Bất_lợi') newPosture = 'Đang_chiến_đấu';
    else if (hp <= 35 && hp > 0 && currentPosture === 'Đang_chiến_đấu') newPosture = 'Bất_lợi';
    if (newPosture && newPosture !== currentPosture) {
        _.set(variables, `stat_data.${posturePath}`, newPosture);
    }
}

function processBossStateMachine(variables) {
    const statePath = 'Thế_giới.Màn_chơi_hiện_tại.Trạng_thái_Boss';
    const toughness = parseInt(_.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', 100), 10) || 0;
    const currentState = _.get(variables.stat_data, statePath);
    let newState = null;
    if (toughness > 50) newState = 'Nguyên_vẹn';
    else if (toughness > 0) newState = 'Dao_động';
    else if (currentState !== 'Gần_chết') newState = 'Sụp_đổ';
    if (newState && newState !== currentState && !['Gần_chết', 'Sụp_đổ'].includes(currentState)) {
        _.set(variables, `stat_data.${statePath}`, newState);
    }
}

function checkVictoryDefeatConditions(variables) {
    const playerHP = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', 100), 10) || 0;
    const bossToughness = parseInt(_.get(variables.stat_data, 'Thế_giới.Màn_chơi_hiện_tại.Độ_bền_Boss', 100), 10) || 0;
    const ultimatePowerUsed = (
        (_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy') === 0 && _.get(scriptState.previousData, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy', 0) >= 100) ||
        (_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế') === 0 && _.get(scriptState.previousData, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế', 0) >= 100)
    );
    if (bossToughness <= 0 || ultimatePowerUsed) {
        return 'Chiến_thắng';
    } else if (playerHP <= 0) {
        _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại', 'Kiệt_sức_chờ_nhục');
        applyAdd(variables, 'Ghi_chép.Tổng_số_lần_thất_bại', 1);
        return 'Thất_bại';
    }
    return null;
}

/**
 * Hồi phục và thông minh hóa chuyển cảnh
 */
function processIntermissionRecovery(variables) {
    // 1. Phục hồi trạng thái cơ bản
    applyAdd(variables, 'Thế_giới.Thời_gian', 1);
    _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Đếm_lượt_chuyển_cảnh', 0); 
    console.log(`[${SCRIPT_NAME}] Phục hồi chuyển cảnh & Thời gian (+1 ngày).`);

    const maxHP = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Tối_đa', 100), 10) || 100;
    const maxMP = parseInt(_.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Tối_đa', 100), 10) || 100;

    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_thể_lực.Hiện_tại', maxHP);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Chỉ_số_ma_lực.Hiện_tại', maxMP);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', false);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Sức_mạnh_thanh_tẩy', 0);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Ma_lực_ô_uế', 0);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại', 'Không_chiến_đấu');
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', 0);
    _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_khoái_cảm.Ngưỡng_cao_trào', 100); 

    // 2. Thiết lập lại bộ phận
    const bodyParts = _.get(variables.stat_data, 'Nhân_vật_chính.Tình_trạng_các_bộ_phận_cơ_thể', {});
    for (const part in bodyParts) {
        if (part === '$meta' || _.get(bodyParts, `${part}.Tình_trạng_hiện_tại`) === 'Không') continue;
        _.set(variables, `stat_data.Nhân_vật_chính.Tình_trạng_các_bộ_phận_cơ_thể.${part}.Tình_trạng_hiện_tại`, 'Không');
    }

    // 3. Đặt lại Màn chơi
    _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Tên', 'Không');
    _.set(variables, 'stat_data.Thế_giới.Sự_kiện_H_chuyển_cảnh.Tên', 'Không'); 

    const themePool = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Nhóm_chủ_đề_tạo_Boss', []).filter(t => t !== '$__META_EXTENSIBLE__$');
    if (themePool.length > 0) {
        const preLockedTheme = _.sample(themePool);
        _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', [preLockedTheme, '$__META_EXTENSIBLE__$']);
        console.log(`[${SCRIPT_NAME}] Nghỉ ngơi chuyển cảnh: Khóa trước Chủ đề Boss -> ${preLockedTheme}`);
    } else {
        _.set(variables, 'stat_data.Thế_giới.Màn_chơi_hiện_tại.Chủ_đề_cốt_lõi', ['$__META_EXTENSIBLE__$']);
    }

    // 4. Khóa sự kiện
    const allKinks = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Sở_thích_tình_dục', {});
    const validKinks = Object.keys(allKinks).filter(k => {
        const d = allKinks[k];
        return k !== '$meta' && d && (d.Cấp_độ >= 1 || d.Kinh_nghiệm >= 50);
    });

    if (validKinks.length > 0) {
        const selected = _.sample(validKinks);
        if (typeof selected !== 'string' || selected.trim() === '') return;

        console.log(`[${SCRIPT_NAME}] Phát hiện có Sở thích (${selected}). Đang khóa sự kiện.`);
        _.set(variables, 'stat_data.Thế_giới.Sự_kiện_H_chuyển_cảnh.Chủ_đề_cốt_lõi', [selected, '$__META_EXTENSIBLE__$']);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh', false);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_phục_hồi_toàn_diện', true);
    } else {
        console.log(`[${SCRIPT_NAME}] Trạng thái tinh khiết. Đang bỏ qua Logic sự kiện H.`);
        _.set(variables, 'stat_data.Thế_giới.Sự_kiện_H_chuyển_cảnh.Chủ_đề_cốt_lõi', ['$__META_EXTENSIBLE__$']);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Hoàn_thành_sự_kiện_chuyển_cảnh', true);
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_phục_hồi_toàn_diện', true);
    }
}

/**
 * Chuyển tiếp tiến trình của game
 */
function advanceGameState(variables) {
    let currentPhase = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn');
    const previousPhase = _.get(scriptState.previousData, 'Tiến_trình.Giai_đoạn');

    if (currentPhase === 'Xử_lý_sau_trận_chiến') {
         const events = _.get(variables.stat_data, 'Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý', {});
         if (!events['Sự_kiện_tiến_hóa_trạng_thái']) {
             _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_tiến_hóa_trạng_thái', true);
         }
    }

    if (currentPhase === 'Nghỉ_ngơi_chuyển_cảnh') {
        const hEventName = _.get(variables.stat_data, 'Thế_giới.Sự_kiện_H_chuyển_cảnh.Tên', 'Không');
        if (hEventName === 'Không') {
            applyAdd(variables, 'Trạng_thái_hệ_thống.Đếm_lượt_chuyển_cảnh', 1);
        }
    } 

    if (currentPhase === 'Chuẩn_bị_chiến_đấu') {
        initializeNewBattle(variables);
        scriptState.turnCounters.defeatPersistence = 0; 

        const isPlayerTransformed = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_biến_hình', false);
        if (isPlayerTransformed === true) {
            console.log(`[${SCRIPT_NAME}] Đã phát hiện biến hình ở giai đoạn Chuẩn bị. Bắt đầu Chiến đấu.`);
            _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', 'Lượt_chiến_đấu');
            currentPhase = 'Lượt_chiến_đấu';
        }
    }

    if (currentPhase === 'Lượt_chiến_đấu') {
        const currentPosture = _.get(variables.stat_data, 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại');
        const validCombatPostures = ['Đang_chiến_đấu', 'Bất_lợi', 'Kiệt_sức_chờ_nhục'];
        if (!validCombatPostures.includes(currentPosture)) {
             _.set(variables, 'stat_data.Nhân_vật_chính.Trạng_thái_cốt_lõi.Tư_thế_chiến_đấu_hiện_tại', 'Đang_chiến_đấu');
        }

        const combatResult = checkVictoryDefeatConditions(variables);
        if (combatResult) {
            _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', combatResult);
            if (combatResult === 'Chiến_thắng') {
                processCombatResultRegistration(variables, scriptState.previousData, 'Chiến_thắng');
            } else if (combatResult === 'Thất_bại') {
                processCombatResultRegistration(variables, scriptState.previousData, 'Thất_bại');
                scriptState.turnCounters.defeatPersistence = 0;
            }
        } else {
            processPlayerStateMachine(variables);
            processBossStateMachine(variables);
        }
    }

    if (currentPhase === 'Thất_bại') {
        scriptState.turnCounters.defeatPersistence += 1;
        if (scriptState.turnCounters.defeatPersistence >= 3) {
            console.log(`[${SCRIPT_NAME}] Đạt giới hạn thất bại. Kích hoạt BAD END.`);
            _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', 'Xử_lý_sau_trận_chiến');
            _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Kết_toán_thất_bại_hoàn_toàn', true);
            _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_tiến_hóa_trạng_thái', true);
            scriptState.turnCounters.defeatPersistence = 0;
            return; 
        }
    }

    const finalPhase = _.get(variables.stat_data, 'Tiến_trình.Giai_đoạn');
    scriptState.turnCounters.finisher = (finalPhase === 'Lượt_kết_liễu') ? scriptState.turnCounters.finisher + 1 : 0;
    scriptState.turnCounters.victory = (finalPhase === 'Chiến_thắng') ? scriptState.turnCounters.victory + 1 : 0;

    if (scriptState.turnCounters.finisher >= 2) {
        _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', 'Chiến_thắng');
        scriptState.turnCounters.finisher = 0;
    }
    if (scriptState.turnCounters.victory >= 3) {
        _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', 'Xử_lý_sau_trận_chiến');
        _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_tiến_hóa_trạng_thái', true); 
        scriptState.turnCounters.victory = 0;
    }

    if (finalPhase === 'Xử_lý_sau_trận_chiến' && finalPhase === previousPhase) {
         console.log(`[${SCRIPT_NAME}] Trận chiến kết thúc. Kích hoạt Kết toán Danh tiếng.`);
         _.set(variables, 'stat_data.Trạng_thái_hệ_thống.Sự_kiện_đang_chờ_xử_lý.Sự_kiện_kết_toán_danh_tiếng_sau_trận', true);
         processIntermissionRecovery(variables);
         _.set(variables, 'stat_data.Tiến_trình.Giai_đoạn', 'Nghỉ_ngơi_chuyển_cảnh');
    }
}

// =================================================================================
// --- 6. Chuẩn bị hiệu lệnh AI ---
// =================================================================================

function preRollNextPlayerAction(variables) {
    if (_.get(variables.stat_data, 'Tiến_trình.Giai_đoạn') !== 'Lượt_chiến_đấu') return;
    const plotBonus = _.get(variables.stat_data, 'Nhân_vật_chính.Chiến_đấu_tạm_thời.Giá_trị_tăng_cường_tạm_thời', 0);
    _.set(variables, 'stat_data.Nhân_vật_chính.Chiến_đấu_tạm_thời.Giá_trị_kiểm_định_người_chơi_mỗi_lượt', (plotBonus > 0) ? 60 + plotBonus : _.random(1, 60));
}

function prepareForAINextTurn(variables) {
    // Để AI chuẩn bị các tính toán...
}

// =================================================================================
// --- 7. Vòng lặp sự kiện chính & Khởi tạo ---
// =================================================================================

function onVariableUpdateEnded(variables) {
    if (!variables?.stat_data?.Tiến_trình || !scriptState.previousData) {
        scriptState.previousData = _.cloneDeep(variables.stat_data);
        console.log(`[${SCRIPT_NAME}] Chạy lần đầu hoặc dữ liệu không hợp lệ. Đã sao lưu trạng thái.`);
        return;
    }

    console.log(`[${SCRIPT_NAME}] ----- Bắt đầu lượt -----`);
    console.log(`[${SCRIPT_NAME}] Chuyển đổi giai đoạn: ${_.get(scriptState.previousData, 'Tiến_trình.Giai_đoạn')} -> ${_.get(variables.stat_data, 'Tiến_trình.Giai_đoạn')}`);

    guardAndSanitizeData(variables);
    processReactiveMechanics(variables);
    processMilestoneCheck(variables, scriptState.previousData); 
    advanceGameState(variables);
    prepareForAINextTurn(variables);

    scriptState.previousData = _.cloneDeep(variables.stat_data);
    console.log(`[${SCRIPT_NAME}] ----- Kết thúc lượt -----`);
}

function initializeEventListeners() {
    if (scriptState.initialized) return;
    try {
        const Mvu = getMvuInstance();
        if (Mvu) {
            scriptState.listeners.onVariableUpdateEnded = onVariableUpdateEnded;
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, scriptState.listeners.onVariableUpdateEnded);
            scriptState.initialized = true;
            console.log(`[${SCRIPT_NAME}] ${SCRIPT_VERSION} Khởi tạo thành công, bắt đầu giám sát.`);
            if (window.toastr) toastr.success(`${SCRIPT_NAME} Đã khởi động`, 'Kịch bản giám sát thẻ nhân vật');
        } else {
            scriptState.retryCount++;
            if (scriptState.retryCount < scriptState.maxRetries) {
                setTimeout(initializeEventListeners, 2000);
            } else {
                if (window.toastr) toastr.error('Không tìm thấy MVU Framework, không thể kích hoạt kịch bản giám sát', 'Lỗi');
            }
        }
    } catch (error) {
        if (window.toastr) toastr.error('Khởi tạo kịch bản giám sát thất bại', 'Lỗi');
    }
}

function cleanup() {
    try {
        const Mvu = getMvuInstance();
        if (Mvu && scriptState.listeners.onVariableUpdateEnded) {
            eventRemoveListener(Mvu.events.VARIABLE_UPDATE_ENDED, scriptState.listeners.onVariableUpdateEnded);
        }
        scriptState.initialized = false;
        scriptState.listeners.onVariableUpdateEnded = null;
        scriptState.retryCount = 0;
        scriptState.previousData = null;
        console.log(`[${SCRIPT_NAME}] Kịch bản đã được dọn dẹp.`);
    } catch (error) {
        console.error(`[${SCRIPT_NAME}] Lỗi xảy ra trong quá trình dọn dẹp:`, error);
    }
}

// Khởi động
$(() => { setTimeout(initializeEventListeners, 1500); });
$(window).on('unload', cleanup);

