[Tùy_chọn] Đầu_ra_bổ_trợ: Tạo_tùy_chọn_người_chơi

<%
// [Hệ_thống] Trình_tạo_tùy_chọn_động
// Chỉ kích hoạt khi nhân vật đã tạo xong
if (_.get(getvar('stat_data'), 'Trạng_thái_hệ_thống.Đã_tạo_xong_nhân_vật_chính') === true) {
    const phase = _.get(getvar('stat_data'), 'Tiến_trình.Giai_đoạn');
    const isCombat = ['Lượt_chiến_đấu', 'Chuẩn_bị_chiến_đấu', 'Lượt_kết_liễu'].includes(phase);
    const corruption = _.get(getvar('stat_data'), 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Độ_ô_nhiễm', 0);
    const pleasure = _.get(getvar('stat_data'), 'Nhân_vật_chính.Trạng_thái_khoái_cảm.Chỉ_số_khoái_cảm', 0);
    const isFallen = _.get(getvar('stat_data'), 'Nhân_vật_chính.Trạng_thái_cốt_lõi.Trạng_thái_nhân_cách') === 'Sa_ngã';

    let desireType = "Bản_năng";
    let desireGuide = "";

    if (isCombat) {
        if (isFallen || corruption > 80) { desireType = "Thích_ngược_đãi"; desireGuide = "【Sa_ngã】 Trêu chọc đối thủ, cố ý để lộ sơ hở, tận hưởng nỗi đau."; }
        else if (pleasure > 50) { desireType = "Dao_động"; desireGuide = "【Thất_hố】 Vì khoái cảm mà rên rỉ, nhũn chân cầu xin tha thứ, liều mạng kìm nén."; }
        else { desireType = "Bùng_nổ"; desireGuide = "【Cảm_xúc】 Sự phẫn nộ, lòng quyết tâm, sự bùng nổ khi bị dồn vào đường cùng."; }
    } else { 
        if (isFallen) { desireType = "Hưởng_lạc"; desireGuide = "【Buông_thả】 Theo đuổi sự kích thích giác quan, những ngày tháng sa ngã kinh doanh sào huyệt."; }
        else { desireType = "Tư_dục"; desireGuide = "【Cá_nhân】 Sở thích, bí mật nhỏ hoặc hành vi thư giãn của một thiếu nữ bình thường."; }
    }
%>
# Chỉ lệnh: Tùy_chọn_hội_thoại_nhanh
options_generator_protocol:
  objective: "Ở cuối phần nội dung chính (trước khối cập nhật biến), hãy tạo một danh sách các hành động mà người chơi có thể lựa chọn."

  format_strict:
    - "Bắt buộc và chỉ được sử dụng định dạng XML sau để bao bọc:"
    - |
      <Tùy_chọn_hành_động>
      Nội_dung_cụ_thể_của_tùy_chọn_1
      Nội_dung_cụ_thể_của_tùy_chọn_2
      Nội_dung_cụ_thể_của_tùy_chọn_3
      Nội_dung_cụ_thể_của_tùy_chọn_4
      </Tùy_chọn_hành_động>
    - "Mỗi dòng đại diện cho một tùy chọn. Không thêm số thứ tự (1.), không thêm dấu ngoặc vuông ([]), chỉ viết văn bản thuần túy."
    - "Nội dung tùy chọn nên là mô tả hành động 【một_câu】 ở 【Ngôi_thứ_nhất】, số lượng từ kiểm soát trong khoảng từ 10-20 từ."

  # Thiết kế tùy chọn: (<%= isCombat ? 'Chế_độ_chiến_đấu' : 'Chế_độ_thường_ngày' %>) 
  option_matrix:
  <%_ if (isCombat) { _%>
    1. [Dũng_mãnh]: "Phát động một cuộc tấn công trực tiếp mang tính rủi ro cao, lợi nhuận cao. Nhắm vào điểm yếu."
    2. [Trí_lược]: "Quan sát chiến cuộc, tận dụng địa hình, đạo cụ hoặc áp dụng tư thế phòng thủ."
    3. [Ma_đạo]: "Sử dụng ma pháp đặc trưng, làm bước đệm cho tuyệt kỹ hoặc triệu hồi sử ma hỗ trợ."
    4. [<%= desireType %>]: "<%= desireGuide %>"
  <%_ } else { _%>
    1. [Hành_động]: "Đi thẳng đến địa điểm mục tiêu, hoặc mở ra chủ đề mới, thúc đẩy tuyến chính."
    2. [Tương_tác]: "Tương tác với các nhân vật xung quanh (sử ma, bạn bè), hoặc kiểm tra cơ thể."
    3. [Khám_phá]: "Điều tra môi trường, nghiên cứu đạo cụ, sắp xếp lại tình trạng."
    4. [<%= desireType %>]: "<%= desireGuide %>"
  <%_ } _%>

  trigger: "Bây giờ, dựa trên ma trận trên, hãy tạo khối <Tùy_chọn_hành_động>."
<%
} 
